export const QB_FED_SYSTEMES = [
  {id:"fed_s1",prompt:"Le protocole KNX (anciennement EIB) est un standard de :",choices:["Plomberie","Domotique et GTB (Gestion Technique du Bâtiment) — bus de communication","Génie climatique uniquement","Sécurité incendie"],answer:1,diff:1,explication:"KNX = protocole de bus domotique standardisé (ISO/IEC 14543). Gère éclairage, chauffage, volets, sécurité, énergie. Topologie en bus (2 fils) ou IP.",tags:["Domotique","KNX","GTB","Protocoles"]},
  {id:"fed_s2",prompt:"Un capteur de présence (détecteur de mouvement) en domotique KNX envoie sur le bus :",choices:["Un signal analogique 4-20 mA","Un télégramme (trame numérique) sur le bus KNX","Un signal 0-10V","Un signal Wi-Fi"],answer:1,diff:2,explication:"KNX : communication par télégrammes numériques sur le bus (TP = paire torsadée ou IP). Chaque composant possède une adresse individuelle et peut communiquer avec des adresses de groupe.",tags:["Domotique","KNX","Télégramme","Capteur"]},
  {id:"fed_s3",prompt:"Dans un système KNX, l'adresse de groupe sert à :",choices:["Identifier physiquement un appareil","Définir la fonction logique (relier un bouton poussoir à un actionneur de lumière)","Paramétrer la vitesse du bus","Identifier le fabricant"],answer:1,diff:2,explication:"Adresse individuelle : localisation physique (1.1.5). Adresse de groupe : association fonctionnelle (entrée/sortie). Un bouton (groupe 0/1/1) commande un actionneur (même adresse de groupe).",tags:["Domotique","KNX","Adressage","Programmation"]},
  {id:"fed_s4",prompt:"Le protocole Modbus est principalement utilisé pour :",choices:["La domotique résidentielle haut de gamme","La communication industrielle et GTB (supervision des équipements techniques)","Les réseaux Wi-Fi","La téléphonie"],answer:1,diff:2,explication:"Modbus RTU/TCP : protocole maître-esclave industriel. Très répandu en GTB pour supervision des automates, compteurs d'énergie, CVC. Simple, robuste, mais peu sécurisé.",tags:["GTB","Modbus","Protocoles industriels","Supervision"]},
  {id:"fed_s5",prompt:"Le BACnet (Building Automation and Control Networks) est un protocole ouvert dédié à :",choices:["La domotique résidentielle","L'automatisation des bâtiments tertiaires (GTB, CVC, énergie)","La vidéosurveillance","La voix sur IP"],answer:1,diff:2,explication:"BACnet (ASHRAE 135) : protocole ouvert pour GTB bâtiments tertiaires. Interopérabilité entre constructeurs. Gère CVC, éclairage, comptage énergie, contrôle d'accès. Peut fonctionner sur IP (BACnet/IP).",tags:["GTB","BACnet","Bâtiment tertiaire","Protocoles"]},
  {id:"fed_s6",prompt:"Une GTB (Gestion Technique du Bâtiment) permet de :",choices:["Uniquement contrôler l'éclairage","Superviser, contrôler et optimiser tous les équipements techniques d'un bâtiment (CVC, éclairage, énergie, sécurité)","Uniquement gérer les accès","Effectuer la maintenance uniquement"],answer:1,diff:1,explication:"GTB : supervision centralisée (postes opérateur), contrôle commande (automates programmables), collecte données (compteurs, capteurs), optimisation énergie, maintenance préventive.",tags:["GTB","Bâtiment","Supervision","Énergie"]},
  {id:"fed_s7",prompt:"Le BIM (Building Information Modeling) est :",choices:["Un logiciel de dessin 2D uniquement","Une maquette numérique tridimensionnelle et collaborative intégrant toutes les données du bâtiment","Un protocole de communication","Un système de ventilation"],answer:1,diff:1,explication:"BIM : maquette numérique 3D + données (matériaux, coûts, planning, équipements). Collaboration entre tous les acteurs (archi, BE, GTB). Logiciels : Revit, ArchiCAD. Niveaux de développement (LOD).",tags:["BIM","Numérique","Collaboration","Bâtiment"]},
  {id:"fed_s8",prompt:"SysML (Systems Modeling Language) est utilisé pour :",choices:["La programmation des automates uniquement","La modélisation des systèmes complexes (diagrammes de blocs, d'exigences, de séquences)","La conception des réseaux Wi-Fi","La modélisation des fluides uniquement"],answer:1,diff:2,explication:"SysML : langage de modélisation pour systèmes complexes. 9 types de diagrammes (exigences, blocs, activités, séquences...). Utilisé en ingénierie systèmes, analyse des exigences.",tags:["SysML","Modélisation","Systèmes complexes","Diagrammes"]},
  {id:"fed_s9",prompt:"Un TGBT (Tableau Général Basse Tension) contient :",choices:["Uniquement des prises électriques","Les protections électriques principales (disjoncteur général, sectionneurs, jeux de barres) et la distribution vers les tableaux divisionnaires","Uniquement des compteurs","Les équipements de domotique"],answer:1,diff:2,explication:"TGBT : armoire électrique principale alimentée depuis le transformateur HTA/BT. Protections principales (disjoncteur général), jeux de barres, départ divisionnaires, compteurs énergie.",tags:["Électrotechnique","TGBT","Distribution électrique","Protection"]},
  {id:"fed_s10",prompt:"La norme NF C 15-100 concerne :",choices:["Les installations de plomberie","Les installations électriques basse tension en France (règles de conception, réalisation, vérification)","Les équipements de ventilation","Les réseaux de communication"],answer:1,diff:1,explication:"NF C 15-100 : norme française pour installations électriques basse tension (locaux d'habitation et tertiaire). Sections de câbles, protections, tableaux, prises, liaisons équipotentielles.",tags:["Électrotechnique","NF C 15-100","Réglementation","Installation électrique"]},
  {id:"fed_s11",prompt:"Un variateur de fréquence (VFD) permet de :",choices:["Protéger contre les courts-circuits","Faire varier la vitesse d'un moteur asynchrone en modifiant la fréquence d'alimentation","Mesurer la puissance consommée","Compenser l'énergie réactive"],answer:1,diff:2,explication:"VFD (Variable Frequency Drive) : convertit la fréquence secteur (50 Hz) en fréquence variable → vitesse moteur variable. Économies d'énergie importantes sur pompes et ventilateurs (loi des ventilateurs).",tags:["Électrotechnique","Variateur","Moteur","Économie d'énergie"]},
  {id:"fed_s12",prompt:"La loi des ventilateurs (affinité) indique que :",choices:["Le débit est proportionnel au carré de la vitesse","La puissance consommée est proportionnelle au cube de la vitesse (P ∝ n³)","La pression est indépendante de la vitesse","Le débit est constant quelle que soit la vitesse"],answer:1,diff:3,explication:"Lois des ventilateurs : Q ∝ n, ΔP ∝ n², P ∝ n³. Réduire la vitesse de 20% → économie de puissance de 50% ! Justifie les variateurs de fréquence en CVC.",tags:["Électrotechnique","Loi des ventilateurs","Variateur","CVC"]},
  {id:"fed_s13",prompt:"Un câble de communication paire torsadée blindée (FTP) se distingue d'un câble non blindé (UTP) par :",choices:["Sa couleur","Sa résistance aux interférences électromagnétiques (EMI) grâce au blindage","Son débit plus faible","Sa couleur rouge obligatoire"],answer:1,diff:1,explication:"FTP (Foiled Twisted Pair) : blindage aluminium autour des paires. Protection contre EMI. Obligatoire en environnement industriel (VDI, bus KNX dans armoires avec variateurs, etc.).",tags:["Réseaux","Câblage","FTP","Perturbations EM"]},
  {id:"fed_s14",prompt:"Le câblage VDI (Voix-Données-Images) en étoile utilise un point de concentration appelé :",choices:["TGBT","Baie de brassage (patch panel) dans un local technique","Box internet","Switch WiFi"],answer:1,diff:1,explication:"VDI en étoile : chaque prise (RJ45) reliée par câble catégorie 6 jusqu'au local technique. Baie de brassage (patch panel) + switch PoE. Permet reconfiguration facile.",tags:["VDI","Câblage structuré","Réseaux","Baie de brassage"]},
  {id:"fed_s15",prompt:"Le protocole DALI (Digital Addressable Lighting Interface) est utilisé pour :",choices:["La gestion du chauffage","Le contrôle numérique de l'éclairage (gradation, groupes, scènes)","La gestion des accès","La supervision des pompes"],answer:1,diff:2,explication:"DALI : protocole numérique dédié à l'éclairage. Adressage individuel de chaque luminaire. Gradation (0-100%), groupes, scènes préprogrammées. Interfaçable avec KNX.",tags:["Domotique","DALI","Éclairage","Gradation"]},
];

export const QB_FED_ENERGIE = [
  {id:"fed_e1",prompt:"La puissance active (P) s'exprime en :",choices:["Volt-Ampères (VA)","Watts (W) — énergie réellement consommée/transformée","Volt-Ampères réactifs (VAR)","Kilowattheures (kWh)"],answer:1,diff:1,explication:"P (W) = puissance active = énergie transformée en chaleur, mécanique, lumière. Q (VAR) = puissance réactive (champs magnétiques). S (VA) = puissance apparente. S² = P² + Q².",tags:["Énergie","Puissance","Électrotechnique"]},
  {id:"fed_e2",prompt:"Le facteur de puissance (cos φ) idéal est :",choices:["0","0.5","1 (toute la puissance apparente est active)","2"],answer:2,diff:1,explication:"cos φ = P/S = 1 → pas de puissance réactive. Si cos φ < 0.93, le distributeur peut pénaliser l'abonné. Compensation par batterie de condensateurs (injection Q capacitive contre Q inductrice des moteurs).",tags:["Énergie","Facteur de puissance","Compensation réactive"]},
  {id:"fed_e3",prompt:"La réglementation thermique RE 2020 succède à la RT 2012 en imposant :",choices:["Uniquement une meilleure isolation","Un bilan carbone positif + confort d'été + seuil énergie primaire (Ep < 100 kWh/m²/an)","L'utilisation obligatoire du gaz","Aucune nouvelle exigence"],answer:1,diff:2,explication:"RE 2020 : 3 indicateurs principaux. 1) IC (Impact Carbone) — bilan carbone du bâtiment. 2) Bbio (besoin bioclimatique). 3) Cep (consommation énergie primaire < 100 kWh/m²/an). Focus sur chaleur d'été.",tags:["Énergie","RE 2020","Thermique","Réglementation"]},
  {id:"fed_e4",prompt:"La pompe à chaleur (PAC) air-air prélève des frigories de l'air extérieur pour :",choices:["Refroidir uniquement en été","Chauffer le bâtiment en hiver (cycle frigorifique inversé)","Produire de l'eau chaude sanitaire uniquement","Ventiler le bâtiment"],answer:1,diff:1,explication:"PAC : cycle frigorifique. En hiver (mode chauffe) : l'évaporateur prélève la chaleur de l'air extérieur, le condenseur restitue la chaleur à l'intérieur. COP > 1 (typiquement 3-4).",tags:["Énergie","Pompe à chaleur","Thermodynamique","COP"]},
  {id:"fed_e5",prompt:"Le COP (Coefficient de Performance) d'une PAC est :",choices:["Toujours inférieur à 1","Le rapport puissance thermique fournie / puissance électrique consommée (COP > 1)","Le taux de compression du frigorigène","La température de la source froide"],answer:1,diff:2,explication:"COP = Pthermique/Pélectrique. COP = 3 : pour 1 kW électrique, 3 kW thermiques fournis (2 kW gratuits prélevés sur l'environnement). SCOP = COP saisonnier (conditions réelles).",tags:["Énergie","COP","PAC","Thermodynamique"]},
  {id:"fed_e6",prompt:"La VMC double flux se distingue de la simple flux par :",choices:["Elle ventile seulement les pièces humides","Elle récupère la chaleur de l'air extrait pour préchauffer l'air neuf entrant (échangeur)","Elle ne filtre pas l'air","Elle consomme plus d'énergie sans bénéfice"],answer:1,diff:2,explication:"VMC double flux : échangeur air-air (rendement > 80%) récupère la chaleur de l'air vicié pour préchauffer l'air neuf. Économie d'énergie + meilleure qualité d'air. Obligatoire en maisons passives.",tags:["Énergie","VMC","Ventilation","Récupération de chaleur"]},
  {id:"fed_e7",prompt:"Le DPE (Diagnostic de Performance Énergétique) classe les bâtiments de :",choices:["A à E","A (< 70 kWh/m²/an) à G (> 420 kWh/m²/an)","1 à 10","Rouge à vert"],answer:1,diff:1,explication:"DPE : étiquette énergie A (très performant, < 70 kWh/m²/an) → G (passoire thermique, > 420 kWh/m²/an). Aussi étiquette GES (CO₂). Opposable depuis 2021. Passoires (F et G) en cours d'interdiction à la location.",tags:["Énergie","DPE","Réglementation","Bâtiment"]},
  {id:"fed_e8",prompt:"L'isolation thermique par l'extérieur (ITE) est préférable à l'isolation par l'intérieur car :",choices:["Elle est moins chère","Elle supprime les ponts thermiques et conserve l'inertie thermique de la structure","Elle est plus rapide à poser","Elle n'existe pas"],answer:1,diff:2,explication:"ITE : isolation enveloppant la structure. Avantages : suppression ponts thermiques (angles, liaisons plancher/mur), conservation inertie thermique de la structure, pas de perte de surface habitable.",tags:["Énergie","Isolation","ITE","Ponts thermiques"]},
  {id:"fed_e9",prompt:"Un compteur communicant Linky permet à ENEDIS de :",choices:["Fixer le prix de l'électricité","Relever la consommation à distance (via CPL), détecter les incidents, activer les options tarifaires","Alimenter le bâtiment directement","Stocker l'énergie solaire"],answer:1,diff:1,explication:"Linky : compteur communicant CPL (Courant Porteur en Ligne). Télé-relevé des données, coupure à distance, activation heures creuses/pointe, détection pannes. 35 millions déployés en France.",tags:["Énergie","Linky","Smart metering","ENEDIS"]},
  {id:"fed_e10",prompt:"La mise à la terre (liaison équipotentielle principale) protège contre :",choices:["Les surintensités","Les contacts indirects (défaut d'isolement vers la masse : la fuite est écoulée à la terre)","Les sous-tensions","La surtension harmonique"],answer:1,diff:2,explication:"Mise à la terre : toutes les masses (parties conductrices d'équipements) reliées à la terre. En cas de défaut d'isolement, le courant s'écoule via la terre → déclenchement disjoncteur différentiel. Protection contact indirect.",tags:["Électrotechnique","Mise à la terre","Protection","Sécurité électrique"]},
  {id:"fed_e11",prompt:"Le schéma TN-S se distingue du TN-C par :",choices:["La présence d'un transformateur","La séparation du neutre (N) et du conducteur de protection (PE) sur tout le circuit (sécurité accrue)","L'absence de prise de terre","La tension d'alimentation"],answer:1,diff:3,explication:"TN-S : N et PE séparés dès l'origine. TN-C : N et PE combinés (PEN). TN-C interdit en France pour installations neuves (NF C 15-100). TN-S préféré pour sa sécurité (courants parasites séparés).",tags:["Électrotechnique","Schéma TN","Neutre","Protection"]},
  {id:"fed_e12",prompt:"Un onduleur (UPS) est utilisé pour :",choices:["Améliorer le facteur de puissance","Alimenter sans interruption des équipements critiques (serveurs, blocs opératoires) en cas de coupure secteur","Convertir le courant continu en courant alternatif photovoltaïque","Stabiliser la tension d'un réseau longue distance"],answer:1,diff:1,explication:"UPS (Uninterruptible Power Supply) : stocke de l'énergie (batteries) et prend le relai en cas de microcoupure ou coupure. Temps d'autonomie variable (minutes à heures). Usage : datacenters, chirurgie, télécom.",tags:["Électrotechnique","UPS","Onduleur","Continuité d'alimentation"]},
  {id:"fed_e13",prompt:"La valeur nominale d'un disjoncteur différentiel résidentiel de type A est choisie pour :",choices:["Détecter uniquement les courants alternatifs sinusoïdaux","Détecter les courants de fuite alternatifs ET pulsatoires (appareils avec alimentations à découpage : lave-linge, TV)","Détecter uniquement les courants continus","Mesurer la consommation électrique"],answer:1,diff:3,explication:"Type AC : courants sinusoïdaux seulement. Type A : sinusoïdaux + pulsatoires (DC pulsé). Obligatoire pour les cuisinières, lave-vaisselle, lave-linge, véhicules électriques (VE). Type F : pour bornes VE.",tags:["Électrotechnique","Disjoncteur différentiel","Type A","Protection"]},
  {id:"fed_e14",prompt:"Un système photovoltaïque raccordé réseau nécessite obligatoirement :",choices:["Un onduleur DC/AC + démarches ENEDIS + convention de raccordement","Uniquement des panneaux solaires","Un compteur Linky spécifique","Un générateur de secours"],answer:0,diff:2,explication:"PV raccordé réseau : onduleur (DC→AC), démarches ENEDIS (dossier CACSI), convention de raccordement, compteur bidirectionnel. L'excédent peut être revendu ou autoconsommé.",tags:["Énergie","Photovoltaïque","Raccordement","ENEDIS"]},
  {id:"fed_e15",prompt:"La thermographie infrarouge en maintenance préventive permet de :",choices:["Mesurer la résistance des câbles","Détecter les points chauds (connexions défectueuses, surchauffes) sans contact","Contrôler l'étanchéité pneumatique","Mesurer le débit des fluides"],answer:1,diff:2,explication:"Thermographie IR : caméra infrarouge détecte les différences de température. Connexions oxydées/desserrées → points chauds → risque incendie. Contrôle TGBT, tableaux électriques, armoires.",tags:["Maintenance","Thermographie","Prévention","Électrotechnique"]},
];

export const QB_FED_PHYSIQUE = [
  {id:"fed_p1",prompt:"La loi d'Ohm pour un circuit résistif pur est :",choices:["U = R × I²","U = R × I (tension = résistance × intensité)","U = I / R","I = U²/R"],answer:1,diff:1,explication:"Loi d'Ohm : U (V) = R (Ω) × I (A). La résistance s'oppose au passage du courant. Puissance dissipée : P = U×I = R×I² = U²/R. Analogie hydraulique : U=pression, I=débit, R=résistance tuyau.",tags:["Électricité","Loi d'Ohm","Résistance","FED"]},
  {id:"fed_p2",prompt:"Les lois de Kirchhoff stipulent :",choices:["Que la tension est la même partout dans le circuit","La loi des nœuds (somme des courants = 0) et la loi des mailles (somme des tensions = 0)","Que la résistance est constante","Que la puissance est toujours maximale"],answer:1,diff:2,explication:"Kirchhoff 1 (nœuds) : ΣI entrants = ΣI sortants. Kirchhoff 2 (mailles) : algèbre des tensions dans une boucle fermée = 0. Base de toute l'analyse des circuits électriques.",tags:["Électricité","Kirchhoff","Circuits","Analyse"]},
  {id:"fed_p3",prompt:"En courant alternatif sinusoïdal 50 Hz, la valeur efficace (RMS) d'une tension de 230 V correspond à une amplitude de :",choices:["230 V","325 V (Umax = Ueff × √2 ≈ 230 × 1.414)","115 V","460 V"],answer:1,diff:2,explication:"Valeur efficace (RMS) = Umax/√2 → Umax = Ueff × √2 ≈ 230 × 1.414 ≈ 325 V. La valeur efficace est l'équivalent continu en termes d'énergie dissipée dans une résistance.",tags:["Électricité","Courant alternatif","Valeur efficace","RMS"]},
  {id:"fed_p4",prompt:"L'énergie stockée par un condensateur est :",choices:["E = L × I²/2","E = C × U²/2 (C en farads, U en volts)","E = R × I²","E = P × t"],answer:1,diff:2,explication:"Condensateur : stocke énergie électrostatique E = ½CU². S'oppose aux variations de tension. En alternatif : réactance Xc = 1/(2πfC). L'inductance stocke E = ½LI² (énergie magnétique).",tags:["Électricité","Condensateur","Énergie","Réactance"]},
  {id:"fed_p5",prompt:"En thermodynamique, le premier principe stipule que :",choices:["L'entropie d'un système isolé augmente toujours","L'énergie totale d'un système fermé est conservée (ΔU = W + Q)","La chaleur ne peut aller que du chaud vers le froid","La température absolue ne peut être négative"],answer:1,diff:2,explication:"1er principe : conservation de l'énergie. ΔU = W (travail) + Q (chaleur). Application : bilan thermique d'un bâtiment (pertes + gains = 0 à l'équilibre). PAC : ΔH = W_compresseur + Q_évaporateur.",tags:["Thermodynamique","Premier principe","Bilan thermique","FED"]},
  {id:"fed_p6",prompt:"La résistance thermique (Rth) d'une paroi est calculée par :",choices:["Rth = λ × e","Rth = e / λ (e = épaisseur en m, λ = conductivité thermique en W/m.K)","Rth = U × I","Rth = λ / e²"],answer:1,diff:2,explication:"Résistance thermique : Rth = e/λ (m²K/W). Plus Rth est élevé, meilleure est l'isolation. Résistances en série s'additionnent (parois multicouches). Coefficient U = 1/ΣRth (W/m²K).",tags:["Thermodynamique","Isolation","Résistance thermique","RE 2020"]},
  {id:"fed_p7",prompt:"Le coefficient de transmission thermique U (anciennement K) s'exprime en :",choices:["W/m.K (conductivité)","W/m²K — flux thermique par unité de surface et de différence de température","kJ/kg.K (chaleur massique)","Pa (pression)"],answer:1,diff:1,explication:"U (W/m²K) = coefficient global de transmission (anciennement K). Mur très isolé : U < 0.15 W/m²K. Fenêtre double vitrage : U ≈ 1.4. Triple vitrage : U ≈ 0.7. RE 2020 impose des valeurs U max par composant.",tags:["Thermodynamique","Coefficient U","Isolation","RE 2020"]},
  {id:"fed_p8",prompt:"La formule de Bernoulli (hydraulique) exprime :",choices:["La conservation de la masse","La conservation de l'énergie dans un fluide parfait (P + ρgh + ½ρv² = constante)","La loi des gaz parfaits","La loi de Darcy"],answer:1,diff:2,explication:"Bernoulli : énergie totale conservée le long d'une ligne de courant. P (pression statique) + ρgh (énergie potentielle) + ½ρv² (énergie cinétique) = constante. Application : Venturi, écoulements dans tuyaux.",tags:["Hydraulique","Bernoulli","Fluides","Mécanique des fluides"]},
  {id:"fed_p9",prompt:"La loi de Poiseuille décrit l'écoulement laminaire dans un tuyau. Le débit volumique Q est proportionnel à :",choices:["La longueur du tuyau","La 4ème puissance du rayon (Q ∝ r⁴) et au gradient de pression","La viscosité","La vitesse de l'écoulement turbulent"],answer:1,diff:3,explication:"Poiseuille : Q = π×r⁴×ΔP / (8×η×L). Doublement du rayon → ×16 le débit ! Explique l'importance du dimensionnement des canalisations. Valable si régime laminaire (Re < 2300).",tags:["Hydraulique","Poiseuille","Débit","Tuyaux"]},
  {id:"fed_p10",prompt:"Le nombre de Reynolds (Re) détermine si un écoulement est :",choices:["Stationnaire ou non","Laminaire (Re < 2300) ou turbulent (Re > 4000), transitoire entre les deux","Compressible ou incompressible","Isotherme ou adiabatique"],answer:1,diff:2,explication:"Re = ρ×v×D/η. Laminaire (< 2300) : couches parallèles, faibles pertes de charge. Turbulent (> 4000) : mélanges, pertes de charge élevées. Transitoire (2300-4000) : instable. Applications : CVC, plomberie.",tags:["Hydraulique","Nombre de Reynolds","Turbulence","Écoulement"]},
  {id:"fed_p11",prompt:"Les pertes de charge régulières dans une canalisation suivent la loi de :",choices:["Bernoulli uniquement","Darcy-Weisbach (ΔP = f × L/D × ρv²/2)","Poiseuille pour les régimes turbulents","Kirchhoff pour les fluides"],answer:1,diff:3,explication:"Darcy-Weisbach : ΔP = f × (L/D) × (ρv²/2). f = facteur de frottement (Moody chart : dépend Re et rugosité). Utilisé pour dimensionner les réseaux de chauffage, climatisation, eau sanitaire.",tags:["Hydraulique","Pertes de charge","Darcy-Weisbach","Dimensionnement"]},
  {id:"fed_p12",prompt:"En acoustique, le niveau de pression sonore en dB est calculé par :",choices:["L = P/P₀","L = 10 × log(I/I₀) en dB (I₀ = 10⁻¹² W/m²)","L = P² × f","L = 20 × log(I/I₀)"],answer:1,diff:2,explication:"Niveau sonore : L = 10×log(I/I₀) dB. Doublement de l'intensité → +3 dB. Doublement de la pression sonore → +6 dB (L = 20×log(p/p₀)). 0 dB = seuil d'audibilité. 140 dB = seuil douleur.",tags:["Acoustique","Décibel","Son","FED"]},
  {id:"fed_p13",prompt:"L'indice d'affaiblissement acoustique Rw mesure :",choices:["L'isolation thermique d'une paroi","La capacité d'une paroi à atténuer la transmission des sons aériens (en dB)","La réverbération d'une salle","L'absorption acoustique d'un matériau"],answer:1,diff:2,explication:"Rw (dB) : isolement aux bruits aériens. Plus Rw est élevé, meillleure l'isolation. Briques pleines : Rw ≈ 50 dB. Cloison plâtre : Rw ≈ 36 dB. Réglementation acoustique NF S 31-032.",tags:["Acoustique","Isolation phonique","Rw","Bâtiment"]},
  {id:"fed_p14",prompt:"La puissance apparente S en triphasé équilibré est :",choices:["S = U×I","S = √3 × U_ligne × I_ligne","S = 3 × P","S = U²/R"],answer:1,diff:3,explication:"Triphasé équilibré : S = √3 × U_L × I_L (VA) ou S = 3 × U_phase × I_phase. Puissance active P = √3 × U_L × I_L × cos φ. Très utilisé en électrotechnique industrielle et tertiaire.",tags:["Électrotechnique","Triphasé","Puissance apparente","FED"]},
  {id:"fed_p15",prompt:"La compensation de l'énergie réactive par batterie de condensateurs permet :",choices:["D'augmenter la tension","D'améliorer le facteur de puissance → réduire les pertes en ligne et éviter les pénalités du distributeur","De stocker l'énergie solaire","D'alimenter le réseau pendant les coupures"],answer:1,diff:2,explication:"Batterie de condensateurs : inject Q capacitive compensant Q inductrice (moteurs). cos φ → 1. Réduit l'intensité dans les câbles (pertes Joule ∝ I²R) et les pénalités énergie réactive du fournisseur.",tags:["Électrotechnique","Énergie réactive","Condensateur","Facteur de puissance"]},
];

export const QB_FED_THERMO2024 = [
  {id:"fed_t1",prompt:"Les 3 modes de transfert thermique sont :",choices:["Conduction, convection et rayonnement","Radiation, advection et diffusion","Absorption, réflexion et transmission","Évaporation, condensation et sublimation"],answer:0,diff:1,explication:"(1) Conduction : transfert dans un solide (ex : mur) par agitation moléculaire. (2) Convection : transfert par mouvement d'un fluide (air chaud qui monte). (3) Rayonnement : transfert électromagnétique (infrarouge) sans milieu matériel (ex : soleil → Terre). En bâtiment, les 3 modes coexistent.",tags:["Thermique","Transfert thermique","Conduction","Convection","Rayonnement"]},
  {id:"fed_t2",prompt:"La résistance thermique d'une paroi monocouche est calculée par :",choices:["Rth = λ/e","Rth = e/λ","Rth = e × λ","Rth = 1/(λ × S)"],answer:1,diff:1,explication:"Rth (m²·K/W) = e (épaisseur en m) / λ (conductivité thermique en W/m·K). Pour une paroi multicouche, les résistances s'additionnent en série : Rtot = ΣRth. Plus Rth est grand, plus l'isolation est bonne.",tags:["Thermique","Résistance thermique","Isolation","Formule"]},
  {id:"fed_t3",prompt:"Le coefficient de transmission thermique U d'une paroi (en W/m²·K) est :",choices:["U = Rtotal × S","U = 1 / R_total","U = λ × e","U = ΔT / Φ"],answer:1,diff:1,explication:"U = 1/Rtotal (W/m²·K). Plus U est petit → paroi mieux isolée. Réglementation RE 2020 : U mur extérieur ≤ 0.20 W/m²·K, U toiture ≤ 0.13, U vitrage ≤ 1.4. Anciennement nommé K.",tags:["Coefficient U","Thermique","Isolation","RE 2020"]},
  {id:"fed_t4",prompt:"Les déperditions thermiques Φ à travers une paroi sont calculées par :",choices:["Φ = U × S × ΔT (avec U en W/m²·K, S en m², ΔT en K)","Φ = λ × e × ΔT","Φ = R × S × ΔT","Φ = S / (R × ΔT)"],answer:0,diff:2,explication:"Φ (W) = U × S × ΔT = S × ΔT / Rtotal. Équivalent à la loi de Fourier en régime permanent. Ex : mur de 100 m² avec U=0.30, ΔT=15K : Φ = 0.30 × 100 × 15 = 450 W.",tags:["Déperditions thermiques","Formule","Φ","Puissance calorifique"]},
  {id:"fed_t5",prompt:"L'eau glycolée (MPG — mono propylène glycol) est utilisée dans les circuits frigorifiques car :",choices:["Elle a un meilleur pouvoir calorifique que l'eau pure","Elle abaisse le point de congélation, protégeant les circuits contre le gel","Elle améliore le transfert de chaleur","Elle est moins corrosive que l'eau"],answer:1,diff:1,explication:"Le MPG (propylène glycol, noté aussi PG) abaisse le point de congélation de l'eau : 30% vol → Tgel ≈ -15°C. Il protège les circuits exposés au froid (terrasses, extérieur). Contrairement à l'éthylène glycol, le MPG est non toxique (utilisé en agroalimentaire). Inconvénient : viscosité plus élevée → calcul Reynolds nécessaire.",tags:["Eau glycolée","MPG","Antigel","Hydraulique FED"]},
  {id:"fed_t6",prompt:"Le nombre de Reynolds Re permet de caractériser le régime d'écoulement. Re est calculé par :",choices:["Re = ρ × v × D / μ (avec ρ masse volumique, v vitesse, D diamètre, μ viscosité dynamique)","Re = v × D / ρ","Re = μ × D / v","Re = P / (ρ × v²)"],answer:0,diff:2,explication:"Re = ρ × v × D / μ (adimensionnel). Régimes : Re < 2300 = laminaire (Poiseuille), 2300 < Re < 4000 = transitoire, Re > 4000 = turbulent. Pour l'eau glycolée (viscosité μ plus élevée), Re est plus faible → régime laminaire plus probable.",tags:["Reynolds","Hydraulique","Régime d'écoulement","FED"]},
  {id:"fed_t7",prompt:"La dureté de l'eau (TH — titre hydrotimétrique) mesure la concentration en :",choices:["Chlorures (Cl⁻) et sulfates (SO₄²⁻)","Ions calcium (Ca²⁺) et magnésium (Mg²⁺)","Nitrates (NO₃⁻)","Dioxyde de carbone dissous"],answer:1,diff:1,explication:"TH = teneur en Ca²⁺ + Mg²⁺ exprimée en degrés français (°f). 1°f = 0.1 mmol/L de CaCO₃ équivalent. Eau douce < 15°f, eau dure > 25°f. L'eau dure forme du tartre (CaCO₃) dans les circuits de chauffage et bouilloires → réduction des échanges thermiques.",tags:["TH","Titre hydrotimétrique","Dureté de l'eau","Chimie eau"]},
  {id:"fed_t8",prompt:"Dans un adoucisseur d'eau à résine échangeuse de cations, la phase de régénération consiste à :",choices:["Filtrer les particules solides avec un filtre mécanique","Injecter de la saumure (eau salée NaCl) pour régénérer la résine saturée en Ca²⁺ et Mg²⁺","Ajouter des antitartre chimiques","Chauffer la résine pour libérer les ions captés"],answer:1,diff:2,explication:"Adoucisseur : résine Na⁺ capte Ca²⁺ et Mg²⁺ → résine se sature. Régénération : saumure NaCl → Na⁺ en excès déplace Ca²⁺/Mg²⁺ → résine rechargée en Na⁺. Phases : (1) adoucissement (R-Na + Ca²⁺ → R-Ca + Na⁺), (2) saturation (capacité épuisée), (3) régénération (retour Na⁺).",tags:["Adoucisseur","Résine échangeuse","Régénération","Chimie eau FED"]},
  {id:"fed_t9",prompt:"La réaction de combustion complète du méthane (CH4) produit :",choices:["CO + H2O (monoxyde de carbone + eau)","CO2 + 2H2O (dioxyde de carbone + eau)","C + H2O (carbone + eau)","CO2 + H2 (dioxyde de carbone + dihydrogène)"],answer:1,diff:1,explication:"CH4 + 2O2 → CO2 + 2H2O (ΔH = -890 kJ/mol). Combustion complète : présence suffisante de O2. Combustion incomplète (manque O2) : formation de CO (monoxyde de carbone) + suies → danger mortel par intoxication au CO (affinité CO-hémoglobine >> O2). Ventilation obligatoire des chaufferies.",tags:["Combustion","Méthane","CH4","CO2","Chaudière"]},
  {id:"fed_t10",prompt:"Le monoxyde de carbone (CO) est dangereux car :",choices:["Il est explosive et s'enflamme spontanément","Il est inodore, incolore et se fixe sur l'hémoglobine avec une affinité 200× supérieure à l'oxygène → intoxication silencieuse","Il est corrosif et attaque les canalisations","Il fait chuter la pression dans les circuits"],answer:1,diff:2,explication:"Le CO (monoxyde de carbone) est produit par la combustion incomplète (manque d'air). Il est inodore et incolore → indétectable sans capteur. Il se fixe sur l'hémoglobine (COHb) 200-240 fois plus fort que O₂ → hypoxie. Cause principale d'intoxications mortelles en habitation (chaudières, poêles). Détecteur CO obligatoire.",tags:["CO","Monoxyde de carbone","Combustion incomplète","Sécurité chaufferie"]},
  {id:"fed_t11",prompt:"Une centrale de traitement d'air (CTA) double flux avec récupérateur de chaleur est utilisée car :",choices:["Elle ne nécessite pas de maintenance","Elle récupère l'énergie de l'air vicié extrait pour préchauffer/prérefroidir l'air neuf entrant, réduisant les consommations de 60 à 90%","Elle filtre les polluants chimiques","Elle humidifie l'air"],answer:1,diff:2,explication:"CTA double flux : l'air extrait (soufflage chaud en hiver) et l'air neuf (froid en hiver) passent dans un échangeur thermique. L'énergie est transférée sans mélange d'air. Rendement échangeur : 60-90%. Obligatoire en RE 2020 pour les bâtiments tertiaires. Les CTA peuvent aussi comporter des batteries de chauffe/refroid et de l'humidification.",tags:["CTA","Double flux","Récupérateur de chaleur","RE 2020","VMC"]},
  {id:"fed_t12",prompt:"En GTB (Gestion Technique du Bâtiment), la régulation d'une installation CVC (Chauffage Ventilation Climatisation) repose typiquement sur :",choices:["Un simple interrupteur marche/arrêt","Un correcteur PID (Proportionnel Intégral Dérivé) qui compare la mesure au point de consigne et calcule une commande corrective","Un minuteur uniquement","Une décision humaine à chaque cycle"],answer:1,diff:2,explication:"Régulation PID : mesure (capteur T°) → comparaison à la consigne (setpoint) → calcul écart (erreur) → correcteur PID → commande sur actionneur (vanne, pompe). P (proportionnel) : action proportionnelle à l'erreur ; I (intégral) : élimine l'erreur statique ; D (dérivé) : anticipe les variations. Utilisé pour la régulation de température, pression, débit en GTB.",tags:["GTB","Régulation PID","CVC","Automatique FED"]},
];

export const QB_FED_PAC = [
  {id:"fed_pac1",prompt:"Une pompe à chaleur (PAC) thermodynamique fonctionne en :",choices:["Brûlant un combustible pour produire de la chaleur","Captant les calories d'une source froide (air, eau, sol) et les restituant à une source chaude grâce à un compresseur électrique","Convertissant directement l'électricité en chaleur par effet Joule","Stockant de l'énergie solaire en journée pour la restituer la nuit"],answer:1,diff:1,explication:"Une PAC capte des calories dans une source froide (air extérieur, eau, sol) et les restitue à une source chaude (logement). Elle utilise un cycle frigorifique alimenté par un compresseur électrique. Le principe : pour 1 kW électrique consommé, elle fournit 3 à 5 kW thermiques.",tags:["PAC","Principe","Cycle frigorifique","Thermodynamique"]},
  {id:"fed_pac2",prompt:"Le COP (Coefficient of Performance) d'une PAC en mode chauffage est défini par :",choices:["COP = P_électrique / P_thermique","COP = P_thermique_utile / P_électrique_consommée","COP = T_source_chaude / T_source_froide","COP = P_froid / P_élec"],answer:1,diff:1,explication:"COP = P_thermique_utile / P_électrique_consommée. Un COP de 4 signifie que pour 1 kW électrique consommé, 4 kW thermiques sont fournis. En mode froid (PAC réversible), on parle d'EER (Energy Efficiency Ratio) = P_froid / P_élec. Le SCOP est le COP saisonnier moyen.",tags:["COP","EER","PAC","Performance"]},
  {id:"fed_pac3",prompt:"Dans le cycle thermodynamique à compression d'une PAC, l'ordre des 4 étapes est :",choices:["Compression → Évaporation → Condensation → Détente","Évaporation → Compression → Condensation → Détente","Condensation → Détente → Évaporation → Compression","Détente → Condensation → Compression → Évaporation"],answer:1,diff:2,explication:"Le cycle frigorifique : (1) Évaporation : fluide absorbe la chaleur de la source froide à basse pression → vaporisation. (2) Compression : compresseur élève la pression et la température du vapeur. (3) Condensation : fluide restitue la chaleur à la source chaude → liquéfaction. (4) Détente : détendeur abaisse la pression pour revenir à l'état initial.",tags:["Cycle frigorifique","Compression","Évaporation","Condensation"]},
  {id:"fed_pac4",prompt:"Le fluide frigorigène R32 remplace progressivement le R410A car :",choices:["Il est moins cher à fabriquer","Son PRG (Potentiel de Réchauffement Global) est de 675 contre 2088 pour le R410A","Il est plus stable chimiquement","Il nécessite une pression plus basse"],answer:1,diff:2,explication:"Le R32 (HFC) a un PRG de 675, bien inférieur aux 2088 du R410A. Le règlement F-gas UE 517/2014 impose des restrictions progressives des fluides à fort PRG. Autres fluides bas-PRG : R290 (propane, PRG=3), R744 (CO₂, PRG=1). Le R22 est déjà interdit depuis 2015.",tags:["Fluides frigorigènes","R32","R410A","PRG","F-gas"]},
  {id:"fed_pac5",prompt:"Le règlement européen F-gas (UE 517/2014 révisé 2024) impose notamment :",choices:["L'utilisation exclusive du R22","Des interdictions progressives des fluides HFC à fort PRG et l'obligation de récupérer les fluides frigorigènes","La suppression de toutes les PAC d'ici 2025","L'utilisation obligatoire du CO₂ comme fluide frigorigène"],answer:1,diff:2,explication:"Le règlement F-gas impose : des quotas puis interdictions progressives des HFC à fort PRG (GWP), la récupération obligatoire des fluides frigorigènes lors des interventions, des certifications pour les techniciens manipulant les fluides. Le R22 est interdit, le R410A est en cours de remplacement.",tags:["F-gas","Réglementation","HFC","PRG","Environnement"]},
  {id:"fed_pac6",prompt:"Une PAC air/air a un COP qui diminue quand la température extérieure baisse parce que :",choices:["Le compresseur consomme plus d'électricité à basse température","L'écart de température entre source froide et source chaude augmente, rendant le cycle moins efficace","Le fluide frigorigène gèle","Les ventilateurs consomment plus d'énergie"],answer:1,diff:2,explication:"Plus l'écart de température ΔT entre source froide (air extérieur) et source chaude (logement) est grand, plus le cycle thermodynamique est pénalisé — le compresseur doit travailler davantage pour élever le niveau d'énergie. Avec T_ext = -5°C et T_intérieur = 20°C, le COP chute. La PAC air/air est également réversible (climatisation en été).",tags:["PAC air/air","COP","Température","Réversible"]},
  {id:"fed_pac7",prompt:"Pour une PAC air/eau couplée à un plancher chauffant, la température d'eau en circuit est typiquement de :",choices:["75-90°C (haute température, comme une chaudière)","35-45°C (basse température, compatible avec un COP élevé)","10-15°C (eau froide)","55-65°C (température intermédiaire)"],answer:1,diff:2,explication:"Le plancher chauffant fonctionne en basse température (35-45°C), ce qui est idéal pour les PAC air/eau car l'écart avec la source froide est réduit → COP élevé (3-4). Les radiateurs classiques fonctionnent à 55-75°C (moins favorable). La RE 2020 encourage les systèmes basse température.",tags:["PAC air/eau","Plancher chauffant","Basse température","COP"]},
  {id:"fed_pac8",prompt:"La PAC géothermique eau/eau capte les calories du sol grâce à :",choices:["Des panneaux solaires thermiques","Des capteurs enterrés (horizontaux en nappe surfacique ou sondes géothermiques verticales)","Des puits artésiens profonds","Des échangeurs dans la ventilation"],answer:1,diff:1,explication:"La PAC géothermique exploite la stabilité thermique du sol (12-15°C toute l'année). Les capteurs horizontaux sont enterrés à 0.8-1.2 m de profondeur (grande surface nécessaire). Les sondes verticales (50-150 m) nécessitent moins de surface mais un forage. Le COP est très élevé (4-5) grâce à la source froide stable.",tags:["PAC géothermique","Capteurs enterrés","Sol","Sonde géothermique"]},
  {id:"fed_pac9",prompt:"Le SCOP (Seasonal COP) se distingue du COP instantané car :",choices:["Il mesure uniquement la performance en été","Il est le COP moyen calculé sur l'ensemble de la saison de chauffe, prenant en compte les températures variables","Il ne tient pas compte de la consommation électrique","Il est toujours supérieur au COP instantané"],answer:1,diff:2,explication:"Le SCOP intègre les variations de température extérieure sur toute la saison (températures douces → COP élevé, températures froides → COP bas). Il est donc plus représentatif de la performance réelle que le COP à une température donnée. La RE 2020 impose un SCOP ≥ 2.5.",tags:["SCOP","COP saisonnier","RE 2020","Performance"]},
  {id:"fed_pac10",prompt:"Un détendeur électronique (par rapport à un détendeur thermostatique) permet :",choices:["D'augmenter la pression du fluide frigorigène","Une régulation plus précise du débit de fluide entre condenseur et évaporateur, améliorant le rendement en charge partielle","De supprimer le besoin de fluide frigorigène","De contrôler la vitesse du compresseur"],answer:1,diff:3,explication:"Le détendeur régule le débit de fluide frigorigène entre condenseur et évaporateur (laminage de pression). Le détendeur électronique (DX ou EEV) est piloté électroniquement avec précision, adapté aux charges partielles. Il améliore le COP sur l'ensemble de la plage de fonctionnement comparé au thermostatique.",tags:["Détendeur","Électronique","Régulation","Rendement partiel"]},
  {id:"fed_pac11",prompt:"Un chiller (groupe de production d'eau glacée) produit typiquement de l'eau à :",choices:["0°C pour congélation","7/12°C pour la climatisation tertiaire (bâtiments de bureaux, hôpitaux)","35-45°C pour le chauffage","55-65°C pour l'eau chaude sanitaire"],answer:1,diff:2,explication:"Le chiller est une PAC en mode froid produisant de l'eau glacée (7°C départ / 12°C retour en standard) pour alimenter des ventilo-convecteurs ou centrales de traitement d'air en tertiaire. Il peut être à condensation à air (plus simple) ou avec tour aéroréfrigérante (meilleur rendement).",tags:["Chiller","Eau glacée","Climatisation","Tertiaire"]},
  {id:"fed_pac12",prompt:"Pour une PAC avec COP = 4 consommant P_élec = 3 kW, la puissance thermique fournie et la puissance captée sur la source froide sont :",choices:["P_chaud = 3 kW, P_froid = 0 kW","P_chaud = 12 kW, P_froid = 9 kW","P_chaud = 4 kW, P_froid = 1 kW","P_chaud = 7 kW, P_froid = 3 kW"],answer:1,diff:2,explication:"Bilan thermique PAC : P_chaud = COP × P_élec = 4 × 3 = 12 kW. P_froid (énergie captée source froide) = P_chaud - P_élec = 12 - 3 = 9 kW. Vérification : P_chaud = P_froid + P_élec → 12 = 9 + 3. C'est la conservation de l'énergie appliquée au cycle frigorifique.",tags:["Bilan thermique","COP","Calcul","PAC"]},
];

export const QB_FED_ELECTRO2 = [
  {id:"fed_el1",prompt:"Le moteur asynchrone triphasé à cage d'écureuil est le plus utilisé en industrie car :",choices:["Il consomme moins d'électricité qu'un moteur à courant continu","Il est robuste, simple (pas de contact glissant), peu onéreux, et facile à alimenter depuis le réseau triphasé","Il tourne exactement à la vitesse de synchronisme","Il ne nécessite aucun démarreur"],answer:1,diff:1,explication:"Le moteur asynchrone triphasé cage d'écureuil (rotor en court-circuit) est universel en industrie/tertiaire : robustesse, absence de balais, faible maintenance. Le glissement s = (Ns-N)/Ns (quelques %). Le courant d'appel au démarrage direct = 5-8 × In, ce qui peut perturber le réseau.",tags:["Moteur asynchrone","Cage d'écureuil","Démarrage","Triphasé"]},
  {id:"fed_el2",prompt:"Un variateur de fréquence (VFD) contrôle la vitesse d'un moteur asynchrone en :",choices:["Modifiant la tension d'alimentation uniquement","Convertissant le courant AC en DC (redresseur), puis en AC de fréquence et tension variables (onduleur)","Modifiant la résistance du stator","Changeant le nombre de pôles du moteur"],answer:1,diff:2,explication:"Le VFD comprend : (1) Redresseur : AC réseau → DC. (2) Filtre capacitif (bus DC). (3) Onduleur IGBT : DC → AC fréquence/tension variables. Le rapport V/f constant maintient le flux magnétique. Génère des harmoniques → nécessite différentiels de type A ou B.",tags:["Variateur de fréquence","VFD","Onduleur","Moteur"]},
  {id:"fed_el3",prompt:"La loi des quadratiques (loi cubique) pour pompes centrifuges et ventilateurs stipule que :",choices:["La puissance est proportionnelle à la vitesse","La puissance absorbée est proportionnelle au CUBE de la vitesse (P ∝ N³)","Le débit est proportionnel au carré de la vitesse","La puissance est indépendante de la vitesse"],answer:1,diff:2,explication:"Lois d'affinité : Q ∝ N, ΔP ∝ N², P ∝ N³. Réduire la vitesse de 20% (N' = 0.8N) → P' = (0.8)³ × P = 0.512P → économie de 48.8% ! C'est pourquoi les variateurs de fréquence sur pompes et ventilateurs CVC sont si efficaces énergétiquement.",tags:["Loi cubique","Ventilateurs","Pompes","Économie d'énergie"]},
  {id:"fed_el4",prompt:"La norme NF C 15-100 régit :",choices:["Les installations électriques haute tension (HTA)","Les installations électriques basse tension en France (conception, réalisation, vérification des locaux résidentiels et tertiaires)","Uniquement les réseaux de communication","Les équipements de protection individuelle électrique"],answer:1,diff:1,explication:"NF C 15-100 : norme française pour les installations électriques BT (≤ 1000 V AC). Elle définit les règles de conception : sections de câbles (tableau B52), types de protections, nombre de prises et circuits, tableaux, liaisons équipotentielles, vérification initiale.",tags:["NF C 15-100","Norme","Installation électrique","BT"]},
  {id:"fed_el5",prompt:"Le schéma de liaison à la terre (SLT) IT se distingue par :",choices:["Le neutre directement mis à la terre","Le neutre isolé de la terre (ou lié par une impédance), ce qui rend la première faute non dangereuse","La séparation du neutre N et du PE","L'absence de disjoncteur différentiel"],answer:1,diff:3,explication:"IT (Isolé Terre) : neutre isolé ou impédant. 1ère faute → pas de courant de défaut → pas de danger immédiat, mais alarme par contrôleur permanent d'isolement (CPI). Utilisé en milieux où la continuité de service est critique (hôpitaux, industrie). TT = neutre direct à la terre (résidentiel France). TN-S = neutre direct + N et PE séparés (tertiaire).",tags:["Schéma TT","TN-S","IT","SLT","Neutre"]},
  {id:"fed_el6",prompt:"Un disjoncteur différentiel de type B (vs type A) est requis pour :",choices:["Les installations résidentielles classiques","Les véhicules électriques et systèmes avec onduleurs pouvant produire des courants de fuite continus","Les éclairages fluorescents","Toutes les installations industrielles"],answer:1,diff:3,explication:"Type AC : courants sinusoïdaux seuls. Type A : + pulsatoires (appareils avec alimentations à découpage). Type B : + courants continus (VE, photovoltaïque, certains variateurs). Le seuil 30 mA protège les personnes (contact indirect), 300 mA protège contre l'incendie.",tags:["Différentiel","Type B","Véhicule électrique","Protection"]},
  {id:"fed_el7",prompt:"La puissance réactive Q (en kVAR) est consommée par :",choices:["Les résistances de chauffage électrique","Les bobines et moteurs électriques (charges inductives) qui créent un champ magnétique","Les ampoules à incandescence","Les alimentations DC des équipements informatiques"],answer:1,diff:2,explication:"P (kW) = puissance active (travail utile). Q (kVAR) = puissance réactive, échangée sans être consommée, nécessaire aux champs magnétiques (moteurs, transformateurs). S (kVA) = √(P²+Q²). cos φ = P/S. Un cos φ bas signifie beaucoup de Q → courant total élevé → pertes Joule → câbles surdimensionnés.",tags:["Puissance réactive","Q","cos φ","Inductif"]},
  {id:"fed_el8",prompt:"La compensation d'énergie réactive par batterie de condensateurs permet de :",choices:["Supprimer les disjoncteurs différentiels","Améliorer le facteur de puissance cos φ → réduire l'intensité dans les câbles et éviter les pénalités tarifaires (cos φ < 0.93)","Stocker l'énergie pour les coupures secteur","Réduire la tension d'alimentation"],answer:1,diff:2,explication:"Les condensateurs injectent de la puissance réactive capacitive Q_C qui compense la Q inductive des moteurs. cos φ → 1 → S se rapproche de P → même puissance utile mais courant I plus faible → pertes Joule ∝ I²R réduites → économies sur facture (pénalité ENEDIS si cos φ < 0.93).",tags:["Compensation réactive","Condensateurs","cos φ","Économie d'énergie"]},
  {id:"fed_el9",prompt:"Le TGBT (Tableau Général Basse Tension) est alimenté directement par :",choices:["Le réseau HTA sans transformation","Le transformateur HTA/BT (ou directement depuis le réseau BT pour les petits bâtiments)","Un groupe électrogène en fonctionnement normal","Les panneaux photovoltaïques"],answer:1,diff:1,explication:"TGBT : armoire principale BT alimentée depuis le transformateur HTA/BT (poste de transformation). Contient : disjoncteur général (protection principale), jeux de barres (distribution), départs divisionnaires (disjoncteurs calibrés), compteurs d'énergie. Protège l'ensemble de l'installation.",tags:["TGBT","Distribution","Transformateur","BT"]},
  {id:"fed_el10",prompt:"Le sous-comptage d'énergie électrique par usage (éclairage, CVC, informatique) est la première étape d'une démarche :",choices:["RE 2020","ISO 50001 (Système de Management de l'Énergie)","NF C 15-100","BIM niveau LOD 400"],answer:1,diff:2,explication:"ISO 50001 : norme de management de l'énergie. Première étape = mesurer les consommations par usage (sous-comptage). Identification des gisements d'économies. Compteurs communicants Modbus ou Linky. Dashboard énergie (kWh/m²/an). Indicateurs de performance énergétique (IPE).",tags:["Comptage d'énergie","ISO 50001","Sous-comptage","Management énergie"]},
  {id:"fed_el11",prompt:"La tarification électrique Tempo (EDF) présente des jours rouges pendant lesquels :",choices:["L'électricité est gratuite","Le kWh est très cher (heures de pointe nationale) — incitation au délestage et au stockage","La puissance souscrite est réduite automatiquement","Le réseau est coupé pour maintenance"],answer:1,diff:2,explication:"Tarif Tempo : 300 jours bleus (bas coût), 43 jours blancs (coût moyen), 22 jours rouges (coût très élevé, x10 par rapport au bleu en HP). Les jours rouges correspondent aux pics de consommation nationaux (vague de froid). Intérêt : délester les gros consommateurs (CVC) en jours rouges → économies importantes.",tags:["Tarification","Tempo","HP/HC","Optimisation tarifaire"]},
  {id:"fed_el12",prompt:"Un luminaire LED avec driver courant constant alimenté en DALI permet :",choices:["Uniquement l'allumage et l'extinction","Un contrôle numérique individuel : gradation 0-100%, adressage unique, scènes préprogrammées, télémaintenance"],answer:1,diff:2,explication:"DALI (Digital Addressable Lighting Interface) : protocole numérique 2 fils, adresse individuelle par luminaire. Driver courant constant : maintient l'intensité LED constante (pas de scintillement). Fonctions : gradation précise, groupes, scènes, détection défauts, intégration GTB/KNX. LED = 80-120 lm/W vs halogène 15 lm/W.",tags:["DALI","LED","Driver","Éclairage","GTB"]},
];

export const QB_FED_GTB2 = [
  {id:"fed_gtb1",prompt:"Le protocole BACnet/IP (ASHRAE 135) se distingue du BACnet MS/TP par :",choices:["BACnet/IP fonctionne uniquement en Wi-Fi","BACnet/IP fonctionne sur TCP/IP (couche 3, réseau Ethernet standard) tandis que MS/TP fonctionne sur RS485 (couche 2, bus série)","BACnet/IP est plus lent","BACnet MS/TP est le seul standard reconnu"],answer:1,diff:2,explication:"BACnet (Building Automation and Control Network) est le standard ASHRAE 135 pour les bâtiments tertiaires. BACnet/IP : couche réseau (Ethernet/IP), longues distances, intégration réseau informatique. MS/TP : bus RS485 2 fils, jusqu'à 127 maîtres, économique. Objets BACnet : Analog Input, Binary Output, Schedule, Trend Log.",tags:["BACnet","BACnet/IP","MS/TP","RS485","Protocoles GTB"]},
  {id:"fed_gtb2",prompt:"Dans Modbus RTU, les 'holding registers' (registres 4xxxx) sont :",choices:["En lecture seule (uniquement mesures)","En lecture et en écriture (consignes, paramètres configurables par le maître)","Réservés aux alarmes","Utilisés uniquement pour le comptage d'énergie"],answer:1,diff:2,explication:"Modbus RTU (RS485) : protocole maître-esclave. Registres : (1) Input registers (3xxxx) = lecture seule (mesures, capteurs). (2) Holding registers (4xxxx) = lecture/écriture (consignes, paramètres). (3) Coils (0xxxx) = sorties TOR R/W. (4) Discrete inputs (1xxxx) = entrées TOR lecture seule. Adresses 1 à 65535.",tags:["Modbus","Holding registers","RTU","Registres"]},
  {id:"fed_gtb3",prompt:"Dans KNX, l'adresse individuelle '1.2.5' signifie :",choices:["Groupe 1, sous-groupe 2, instance 5 (adresse fonctionnelle)","Zone 1, ligne 2, appareil 5 (localisation physique de l'appareil sur le bus)","Bâtiment 1, étage 2, local 5","Version 1.2 du firmware, appareil 5"],answer:1,diff:2,explication:"KNX adresse individuelle = zone.ligne.appareil (ex: 1.2.5 = zone 1, ligne 2, appareil 5). Cette adresse identifie physiquement l'emplacement. L'adresse de groupe (ex: 0/1/1) relie fonctionnellement des émetteurs et récepteurs (bouton → actionneur de lumière). Programmation via ETS (Engineering Tool Software).",tags:["KNX","Adresse individuelle","Adresse de groupe","ETS"]},
  {id:"fed_gtb4",prompt:"Les langages de programmation des automates (IEC 61131-3) incluent le Ladder (LD), qui est :",choices:["Un langage texte structuré similaire au Pascal","Une représentation graphique en échelle (contacts et bobines) inspirée des schémas électriques à relais","Un langage de blocs fonctionnels","Un diagramme d'états séquentiels"],answer:1,diff:2,explication:"IEC 61131-3 définit 5 langages API : Ladder (LD) = schémas à contacts électriques ; FBD (Function Block Diagram) = blocs fonctionnels ; ST (Structured Text) = texte Pascal-like ; IL (Instruction List) = assembleur ; SFC (Sequential Function Chart) = Grafcet pour processus séquentiels. Le cycle automate : lecture E/S → traitement → écriture sorties.",tags:["API","PLC","Ladder","IEC 61131","Automate"]},
  {id:"fed_gtb5",prompt:"La GTC (Gestion Technique Centralisée) d'un bâtiment permet notamment de :",choices:["Uniquement commander l'éclairage","Superviser en temps réel toutes les installations (synoptiques, alarmes, historiques, courbes de tendance) via OPC-UA","Réaliser les travaux de maintenance","Programmer les accès des occupants"],answer:1,diff:1,explication:"La GTC offre : synoptiques animés (vue temps réel), gestion des alarmes (avec acquittement), historique des données (trends), rapports énergétiques. Le standard OPC-UA (Unified Architecture) permet l'interopérabilité entre automates, superviseurs et systèmes IoT. Protocoles sous-jacents : Modbus, BACnet, KNX.",tags:["GTC","Supervision","OPC-UA","Alarmes","Synoptiques"]},
  {id:"fed_gtb6",prompt:"Une régulation tout-ou-rien (TOR) avec hystérésis commande une chaudière avec Tconsigne = 20°C et hystérésis ±1°C. La chaudière s'allume à :",choices:["20°C exactement (pas d'hystérésis)","19°C (chaudière ON) et s'éteint à 21°C (chaudière OFF)","18°C et s'éteint à 22°C","21°C et s'éteint à 19°C"],answer:1,diff:1,explication:"TOR avec hystérésis : bande morte autour de la consigne évitant un fonctionnement marche/arrêt trop fréquent (usure). Avec ±1°C : chaudière ON quand T < 19°C, OFF quand T > 21°C. L'hystérésis est un compromis entre confort (bande étroite) et durée de vie équipement (bande large). Inconvénient : oscillations autour de la consigne.",tags:["Régulation TOR","Hystérésis","Thermostat","Chaudière"]},
  {id:"fed_gtb7",prompt:"Un correcteur proportionnel (P) présente une erreur statique résiduelle car :",choices:["Il oscille sans jamais se stabiliser","La commande u = Kp × erreur : quand l'erreur est nulle, la commande est nulle — or il faut une commande non nulle pour maintenir l'équilibre, donc une erreur permanente subsiste","Il n'est pas adapté aux systèmes lents","Il fait osciller le système"],answer:1,diff:3,explication:"Correcteur P : u = Kp × e(t). En régime permanent, pour maintenir une vanne à 30% d'ouverture, il faut u = 30% ≠ 0, donc e ≠ 0 → écart permanent de consigne (bande proportionnelle). L'action intégrale (I) élimine cette erreur statique en accumulant l'erreur dans le temps : u_I = Ki × ∫e dt.",tags:["Régulation P","Erreur statique","Proportionnel","Automatique"]},
  {id:"fed_gtb8",prompt:"Dans un correcteur PID, l'action dérivée (D) permet de :",choices:["Annuler l'erreur statique résiduelle","Anticiper les variations rapides de la mesure (réagit à la vitesse de variation de l'erreur de/dt), améliorant la stabilité et la rapidité","Augmenter le gain statique","Compenser les perturbations constantes"],answer:1,diff:2,explication:"PID = P + I + D. Action D = Kd × de/dt : réagit à la vitesse de changement de l'erreur. Si la mesure monte rapidement vers la consigne, D anticipe et réduit la commande → moins de dépassement. Utilité : systèmes avec inertie (grandes pièces, grand volume d'eau). Inconvénient : amplifie le bruit de mesure → filtrage nécessaire.",tags:["PID","Action dérivée","Anticipation","Stabilité"]},
  {id:"fed_gtb9",prompt:"Un capteur PT1000 en GTB mesure :",choices:["La pression différentielle","La température par variation de résistance électrique (résistance = 1000 Ω à 0°C, variation ~3.85 Ω/°C)","L'humidité relative","Le débit volumique"],answer:1,diff:2,explication:"PT1000 (et PT100) : sondes à résistance de platine (RTD). PT1000 : R = 1000 Ω à 0°C (PT100 = 100 Ω à 0°C). Variation linéaire : ~3.85 Ω/°C. Signal analogique 4 fils (précision) ou 2 fils. Avantages : précision, stabilité, large plage. Autres capteurs GTB : 4-20 mA (température, pression, CO₂ NDIR), 0-10V, contacts TOR.",tags:["PT1000","Capteur température","RTD","Analogique"]},
  {id:"fed_gtb10",prompt:"Un compteur d'eau avec sortie impulsion fournit 1 impulsion par litre. Pour mesurer un débit de 2 m³/h, la fréquence d'impulsions attendue est :",choices:["2 impulsions/min","33.3 impulsions/min (2000 L/h ÷ 60 min/h)","120 impulsions/min","1 impulsion/seconde"],answer:1,diff:2,explication:"2 m³/h = 2000 L/h = 2000 L/60 min = 33.33 L/min → 33.33 impulsions/min. La GTB compte les impulsions par unité de temps pour calculer le débit, et cumule les impulsions pour le volume total. Compteurs d'énergie thermique (calorie) : similaire + mesure ΔT. Compteurs électriques communicants : Modbus.",tags:["Compteur d'eau","Impulsion","Débit","Calcul GTB"]},
  {id:"fed_gtb11",prompt:"Le câblage structuré VDI en topologie étoile impose une distance maximale entre la prise murale et le panneau de brassage de :",choices:["50 m","90 m pour le câble de distribution (+ 10 m de cordons = 100 m total)","150 m","200 m avec câble Cat 7"],answer:1,diff:1,explication:"Standard câblage structuré (ISO 11801 / EN 50173) : distance max poste de travail = 100 m total. Décomposé en : 90 m câble horizontal (de la prise murale au panneau de brassage) + 5 m cordon côté baie + 5 m cordon côté utilisateur. Cat 6A (500 MHz) supporte 10 Gbit/s sur 100 m. Topologie étoile centralisée sur baie 19\".",tags:["VDI","Câblage structuré","Cat 6A","Baie de brassage","100m"]},
  {id:"fed_gtb12",prompt:"LoRaWAN est utilisé en smart building pour :",choices:["Le câblage des capteurs dans les armoires électriques","Des capteurs sans-fil à longue portée et très faible consommation (T°, CO₂, occupation), communiquant via des passerelles vers des plateformes cloud (MQTT/REST)","La communication vidéosurveillance","Le contrôle des variateurs de fréquence"],answer:1,diff:2,explication:"LoRaWAN (Long Range Wide Area Network) : réseau sans-fil IoT, portée 1-15 km, débit faible (250 bps à 50 kbps), batterie 5-10 ans. Idéal pour capteurs dispersés dans un bâtiment ou campus. Alternative : Zigbee (courte portée, maillé). Plateformes cloud : The Things Network, AWS IoT. Protocoles applicatifs : MQTT, REST API.",tags:["LoRaWAN","IoT","Smart building","Capteurs sans-fil","MQTT"]},
];

// ─── BANQUE QB_FED_THERMIQUE_BAT ───
export const QB_FED_THERMIQUE_BAT = [
  {id:"fed_tb1",prompt:"Les déperditions totales d'un bâtiment (ΦT) sont la somme de :",choices:["Uniquement les pertes par les murs extérieurs","Les déperditions par transmission (parois, ponts thermiques) + par renouvellement d'air (ventilation + infiltrations)","Les déperditions par les fenêtres uniquement","Les déperditions par convection naturelle uniquement"],answer:1,diff:1,explication:"ΦT = ΦT_transmission + ΦT_renouvellement d'air. Transmission : parois (murs, toit, plancher bas, fenêtres) + ponts thermiques linéiques (ψ × L). Renouvellement d'air : débit × ρair × Cp_air × ΔT. La méthode de calcul est définie par la méthode Th-BCE (RT 2012/RE 2020).",tags:["Thermique bâtiment","Déperditions","Transmission","Ventilation"]},
  {id:"fed_tb2",prompt:"Un pont thermique linéique (ψ en W/m·K) apparaît principalement :",choices:["Au centre d'un mur bien isolé","Aux liaisons entre parois (plancher/mur, refend/façade, acrotère/toit) où l'isolant est interrompu ou réduit","Dans les vitrages à faible émissivité","Dans les ventilateurs de VMC"],answer:1,diff:2,explication:"Ponts thermiques : discontinuités de l'isolation aux jonctions (angles, refends, menuiseries). ψ (W/m·K) = coefficient linéique du pont thermique. Déperdition : ΦPT = ψ × L × ΔT. L'ITE (isolation thermique par l'extérieur) supprime la majorité des ponts thermiques structurels.",tags:["Pont thermique","ψ linéique","Isolation","ITE"]},
  {id:"fed_tb3",prompt:"Le Bbio (Besoin Bioclimatique) de la RE 2020 mesure :",choices:["La consommation d'énergie primaire annuelle du bâtiment","Les besoins de chauffage, refroidissement et éclairage intrinsèques du bâtiment (indépendamment des systèmes)","L'empreinte carbone du bâtiment sur 50 ans","Le débit de ventilation minimum réglementaire"],answer:1,diff:2,explication:"Bbio (exprimé en Bbio-points) = indicateur bioclimatique RE 2020 évaluant les besoins de chauffage + refroidissement + éclairage du bâtiment seul (enveloppe, orientation, compacité, surfaces vitrées). Il encourage l'architecture bioclimatique avant même les systèmes techniques. Bbio_max à respecter.",tags:["RE 2020","Bbio","Bioclimatique","Enveloppe"]},
  {id:"fed_tb4",prompt:"L'inertie thermique d'un bâtiment à forte masse (béton, pierre) permet :",choices:["D'augmenter les déperditions hivernales","De stocker la chaleur/fraîcheur et d'amortir les variations de température extérieure (déphasage thermique) → confort d'été amélioré","D'accélérer le chauffage par effet Joule","De réduire la ventilation nécessaire"],answer:1,diff:2,explication:"Inertie thermique : capacité d'un matériau à stocker et restituer la chaleur. Caractérisée par l'effusivité (b = √(λρCp)) et la diffusivité (a = λ/ρCp). Fort déphasage (> 10h) : le pic de chaleur extérieur arrive très atténué la nuit. RE 2020 valorise l'inertie pour le confort d'été (IC_été).",tags:["Inertie thermique","Déphasage","Confort d'été","RE 2020"]},
  {id:"fed_tb5",prompt:"La valeur maximale du coefficient U pour un vitrage neuf en RE 2020 (maison individuelle) est de :",choices:["0.80 W/m²·K","1.40 W/m²·K pour les vitrages neufs (double vitrage à faible émissivité)","2.50 W/m²·K (simple vitrage)","0.50 W/m²·K (standard triple vitrage)"],answer:1,diff:2,explication:"RE 2020 : Uw (vitrage + cadre) ≤ 1.40 W/m²·K pour les menuiseries. Triple vitrage : Uw ≈ 0.7 W/m²·K. Simple vitrage : Uw ≈ 5.8 W/m²·K. Le facteur solaire g du vitrage influe aussi sur le bilan thermique (apports solaires passifs en hiver, protection en été).",tags:["Coefficient U","Vitrage","RE 2020","Double vitrage"]},
  {id:"fed_tb6",prompt:"Le flux thermique à travers une paroi multicouche (mur de 20 cm béton λ=1.8 + 12 cm laine de roche λ=0.04) avec ΔT = 15°C est de :",choices:["Environ 5 W/m²","Environ 4.1 W/m² (Rtot = 0.111 + 3 = 3.111 m²K/W → U = 0.321 → Φ = 0.321 × 15 ≈ 4.8 W/m²)","Environ 50 W/m²","Environ 0.5 W/m²"],answer:1,diff:3,explication:"Calcul : R_béton = 0.20/1.8 = 0.111 m²K/W. R_LDR = 0.12/0.04 = 3.0 m²K/W. Rtot = 0.111 + 3.0 = 3.111 m²K/W (sans les résistances superficielles ≈ 0.17). U ≈ 1/3.28 ≈ 0.305 W/m²K. Φ = U × ΔT ≈ 0.305 × 15 ≈ 4.6 W/m². Sans l'isolant : Φ = (1.8/0.20) × 15 = 135 W/m² → l'isolation divise le flux par ~30.",tags:["Calcul thermique","Flux","Résistance thermique","Application numérique"]},
  {id:"fed_tb7",prompt:"L'étiquette Energie DPE est passée à opposable depuis 2021. Une 'passoire thermique' est classée :",choices:["A ou B","F ou G (> 330 kWh/m²/an en énergie primaire ou > 70 kg CO₂/m²/an)","C ou D","E uniquement"],answer:1,diff:1,explication:"DPE obligatoire et opposable depuis 01/07/2021 (réforme). Classes : A (< 70), B (70-110), C (111-180), D (181-250), E (251-330), F (331-420), G (> 420 kWh/m²/an). G et F = passoires thermiques. Interdiction progressive de location : G en 2025, F en 2028, E en 2034.",tags:["DPE","Passoire thermique","Réglementation","Logement"]},
  {id:"fed_tb8",prompt:"Le ratio entre les apports de chaleur internes et solaires gratuits (apports/pertes) dans le bilan thermique d'un bâtiment influence :",choices:["Uniquement la consommation d'eau chaude sanitaire","Le besoin réel de chauffage (besoins = déperditions - apports gratuits) → réduit la puissance de chauffage nécessaire","Le niveau sonore de la VMC","La résistance mécanique des parois"],answer:1,diff:2,explication:"Bilan thermique : Besoins de chauffage = Déperditions - Apports gratuits (solaires + internes). Apports solaires (orientations S/SE/SO, facteur g vitrage), apports internes (occupants ≈ 80 W, électroménager, éclairage). Un bâtiment bioclimatique maximise ces apports → réduit la consommation de chauffage.",tags:["Bilan thermique","Apports solaires","Apports internes","Bioclimatique"]},
  {id:"fed_tb9",prompt:"La méthode des 5 usages réglementaires de la RE 2020 (pour le calcul Cep) comprend :",choices:["Chauffage, ECS, éclairage, VMC, domotique","Chauffage, refroidissement, eau chaude sanitaire, éclairage, auxiliaires (pompes, ventilateurs)","Chauffage, PAC, photovoltaïque, VMC, cuisine","Chauffage, isolation, vitrage, plancher, toiture"],answer:1,diff:2,explication:"RE 2020 (5 usages réglementaires) : (1) Chauffage, (2) Refroidissement, (3) ECS (eau chaude sanitaire), (4) Éclairage, (5) Auxiliaires (ventilateurs, pompes de circulation, régulation). Cep (consommation d'énergie primaire) en kWh_ep/m²/an. Coefficients d'énergie primaire : élec = 2.3, gaz = 1.0, bois = 0.6.",tags:["RE 2020","5 usages","Cep","Énergie primaire"]},
  {id:"fed_tb10",prompt:"Un label BEPOS (Bâtiment à Énergie POSitive) signifie que :",choices:["Le bâtiment ne consomme pas d'eau chaude sanitaire","La production d'énergie renouvelable sur site est supérieure à la consommation des 5 usages réglementaires","Le bâtiment est entièrement autonome en eau","Il n'y a aucune émission de CO₂ pendant la construction"],answer:1,diff:2,explication:"BEPOS (ou E+C- niveau E3-E4) : production locale d'EnR (PV, éolien, géothermie) > consommation réglementaire. Précurseur de la RE 2020. Label E+C- : 4 niveaux d'énergie (E1→E4) + 2 niveaux carbone (C1, C2). BEPOS = E3 ou E4 + bonne isolation + production EnR.",tags:["BEPOS","Énergie positive","E+C-","EnR"]},
  {id:"fed_tb11",prompt:"L'efficacité d'un isolant est principalement caractérisée par :",choices:["Sa densité (kg/m³) uniquement","Sa conductivité thermique λ (W/m·K) : plus λ est faible, plus l'isolant est performant","Sa couleur et son aspect de surface","Sa résistance au feu uniquement"],answer:1,diff:1,explication:"λ (W/m·K) = conductivité thermique. Valeurs typiques : laine de verre λ ≈ 0.035-0.04, laine de roche λ ≈ 0.033-0.040, PSE (polystyrène expansé) λ ≈ 0.030-0.038, polyuréthane λ ≈ 0.022-0.025. Les matériaux naturels (ouate de cellulose λ ≈ 0.038, liège λ ≈ 0.040) ont des performances comparables.",tags:["Conductivité thermique","λ","Isolant","Matériaux"]},
  {id:"fed_tb12",prompt:"Le test de perméabilité à l'air (blower door test) d'un bâtiment mesure :",choices:["Le débit de ventilation de la VMC en fonctionnement normal","Le débit de fuite d'air à 4 Pa et à 50 Pa sous-pression pour évaluer l'étanchéité à l'air de l'enveloppe","La résistance thermique des murs","La puissance consommée par le système de chauffage"],answer:1,diff:2,explication:"Test de perméabilité (n50 en vol/h ou Q4Pa_surf en m³/h.m²) : mesure de l'étanchéité à l'air de l'enveloppe. BBC Effinergie : Q4Pa ≤ 0.60 m³/h.m² (maison) ou 1.0 (appartement). RE 2020 : exigence renforcée. Infiltrations = déperditions non contrôlées + inconfort. Joints d'étanchéité (ITI+pare-vapeur).",tags:["Perméabilité à l'air","Blower door","Étanchéité","BBC"]},
];

// ─── BANQUE QB_FED_AERO_VENTIL ───
export const QB_FED_AERO_VENTIL = [
  {id:"fed_av1",prompt:"La VMC simple flux hygroréglable de type B (SF-B) module les débits d'air en fonction de :",choices:["La température extérieure uniquement","L'humidité relative de l'air dans les pièces (bouches hygrorégables sensibles à l'HR)","La consommation électrique des occupants","Le taux de CO₂ ambiant"],answer:1,diff:2,explication:"VMC SF-B (hygroréglable type B) : extraction variable dans les pièces humides (bouches d'extraction hygrorégables) ET entrées d'air modulées dans les pièces sèches. Plus économique que la DF (double flux) mais moins efficace énergétiquement. SF-A : débits fixes. Réglementation : arrêté du 24 mars 1982 modifié.",tags:["VMC","Simple flux","Hygroréglable","Ventilation"]},
  {id:"fed_av2",prompt:"Les débits réglementaires minimaux d'extraction d'air en VMC pour une cuisine sont définis par :",choices:["Le DTU 45.11 uniquement","L'arrêté du 24 mars 1982 (modifié) et le DTU 68.3 : cuisine = 45 m³/h minimum en débit maximal (hygro-B) ou 90 m³/h (débit fixe)","La RE 2020 uniquement","Le fabricant de la VMC"],answer:1,diff:2,explication:"DTU 68.3 (VMC) et arrêté du 24 mars 1982 : débits réglementaires selon le nombre de pièces principales. Cuisine : 45-90 m³/h (SF-A fixe). Salle d'eau : 15-30 m³/h. WC : 15 m³/h. Entrées d'air dans pièces de vie (séjour, chambres). Principe : tirage de l'air des pièces sèches vers les pièces humides.",tags:["VMC","Débit d'air","DTU 68.3","Réglementation ventilation"]},
  {id:"fed_av3",prompt:"L'efficacité thermique d'un échangeur à flux croisés d'une VMC double flux est typiquement de :",choices:["20-30% (faible performance)","75-95% selon la qualité de l'échangeur (récupérateur à plaques ou rotatif)","50% uniquement (standard réglementaire)","100% (récupération totale de la chaleur)"],answer:1,diff:2,explication:"VMC double flux : échangeur à contre-courant ou flux croisés (ou rotatif enthalpique). Récupération 75-95% de la chaleur de l'air extrait. Exemple : T_ext = 0°C, T_int = 20°C, rendement 80% → T_air neuf préchauffé = 16°C. BBC et RE 2020 imposent une récupération ≥ 75% pour le tertiaire.",tags:["VMC double flux","Échangeur","Récupération chaleur","Rendement"]},
  {id:"fed_av4",prompt:"Une Centrale de Traitement d'Air (CTA) en tertiaire assure :",choices:["Uniquement la ventilation mécanique","Le traitement hygrothermique complet de l'air (filtration, chauffage/refroidissement, humidification/déshumidification, récupération d'énergie)","Uniquement la filtration de l'air","La distribution d'eau glacée dans les ventilo-convecteurs"],answer:1,diff:1,explication:"CTA (Unité de Traitement d'Air = UTA) : filtration (G4/F7/H13), chauffage (batterie eau chaude/résistance), refroidissement (batterie eau glacée/DX), humidification (vapeur, adiabatique), récupération chaleur (roue ou plaques), by-pass. Régulation des débits via volets motorisés et variateurs (VFD sur moto-ventilateurs).",tags:["CTA","UTA","Traitement d'air","Tertiaire"]},
  {id:"fed_av5",prompt:"Les pertes de charge singulières (accessoires, coudes, réductions) dans un réseau aéraulique sont exprimées en :",choices:["Pascals directement par la loi de Darcy","ΔPs = ξ × ρv²/2 (Pa), où ξ est le coefficient de perte de charge singulière (adimensionnel)","Watts par mètre de conduit","En m³/h divisé par la section"],answer:1,diff:3,explication:"Pertes de charge dans les conduits : régulières ΔPr = f × L/D × ρv²/2 (Darcy-Weisbach) ; singulières ΔPs = ξ × ρv²/2. ξ dépend du type d'accessoire (coude 90° : ξ ≈ 0.5-1.0). La pression dynamique Pdyn = ρv²/2 (Pa). Vitesse max recommandée : 6-8 m/s (galerie principale), 3-4 m/s (terminaux).",tags:["Aéraulique","Pertes de charge","Singulières","Conduits"]},
  {id:"fed_av6",prompt:"La vitesse recommandée dans un conduit de ventilation tertiaire (galerie principale) ne doit pas dépasser :",choices:["2 m/s (pour éviter le bruit)","6-8 m/s en galerie principale (compromis vitesse/pression sonore/perte de charge)","20 m/s (vitesse industrielle)","0.5 m/s (tirage naturel uniquement)"],answer:1,diff:2,explication:"Recommandations aérauliques : galeries principales 6-8 m/s, distributions secondaires 4-6 m/s, bouches de soufflage/extraction 2-4 m/s (confort). Au-delà de 8 m/s : pertes de charge quadratiques excessives et bruit aéraulique (Lw ↑). Dimensionnement selon abaque de Carrier ou calcul Darcy-Weisbach.",tags:["Aéraulique","Vitesse","Conduits","Bruit"]},
  {id:"fed_av7",prompt:"Un filtre G4 dans une CTA correspond à :",choices:["Un filtre haute efficacité HEPA","Un filtre grossier (efficacité ISO ePM10 > 50%) retenant les grosses particules (pollen, insectes)","Un filtre absolu (efficacité > 99.97%)","Un filtre à charbon actif pour les odeurs"],answer:1,diff:2,explication:"Classification EN ISO 16890 (remplace EN 779) : ePM10 > 50% = G4 (grossier, anciennement EU4). ePM2.5 > 50% = M5/F6 (médium). ePM1 > 50% = F7/F8 (fin). HEPA H13 : > 99.95% (salle propre, bloc opératoire). CTA standard : pré-filtre G4 + filtre M5/F7. Air filtration = qualité de l'air intérieur (QAI).",tags:["Filtre","CTA","G4","EN ISO 16890"]},
  {id:"fed_av8",prompt:"Le taux de renouvellement d'air (TRA) recommandé dans un bureau occupé est de :",choices:["0.1 vol/h (très faible, air stagnant)","25-36 m³/h/personne selon la norme NF EN 13779 (équivalent 1-2 vol/h selon la surface)","100 m³/h/personne","1 vol/h uniquement pour les locaux humides"],answer:1,diff:2,explication:"NF EN 13779 (ventilation bâtiments non résidentiels) : qualité d'air IDA 2 (bonne) = 36 m³/h/pers, IDA 3 (moyenne) = 25 m³/h/pers. Taux CO₂ en occupation : IDA2 < 800 ppm, IDA3 < 1000 ppm. Le RSDT (rapport de soufflage) et le brassage influencent l'efficacité de la ventilation.",tags:["Taux renouvellement","Bureau","NF EN 13779","QAI"]},
  {id:"fed_av9",prompt:"La ventilation nocturne (free cooling nocturne) en été permet de :",choices:["Réduire la consommation de chauffage en hiver","Évacuer les calories stockées dans l'inertie thermique du bâtiment en faisant circuler l'air frais nocturne → recharge le bâtiment en fraîcheur pour le lendemain","Augmenter le débit VMC pendant la nuit pour la qualité de l'air","Éviter la condensation sur les murs en hiver"],answer:1,diff:2,explication:"Free cooling : en été, lorsque T_ext nocturne < T_int, on augmente massivement le débit d'air (2-5 vol/h) pour refroidir l'inertie thermique du bâtiment (dalle, murs). Le bâtiment 'recharge' en fraîcheur → confort diurne amélioré sans climatisation. Nécessite une inertie forte et un pilotage GTB intelligent.",tags:["Free cooling","Ventilation nocturne","Inertie","Confort été"]},
  {id:"fed_av10",prompt:"Le débit extrait par un extracteur de cuisine à hotte doit être :",choices:["Égal au débit d'air soufflé dans la pièce","Suffisant pour capter les graisses et odeurs (150-400 m³/h), avec un filtre anti-graisse et rejet à l'extérieur ou recyclage à charbon actif","Inférieur au débit de ventilation de la pièce","Uniquement en fonctionnement permanent"],answer:1,diff:1,explication:"Hotte de cuisine : débit 150-400 m³/h selon largeur. Filtre anti-graisse (métal lavable). Rejet direct extérieur : le plus efficace (pas de recyclage de l'humidité). Hotte recyclage (filtre charbon actif) : moins efficace en humidité, utilisée si rejet impossible. La hotte n'est pas substituable à la VMC (différents systèmes).",tags:["Hotte","Cuisine","Extraction","Graisse"]},
  {id:"fed_av11",prompt:"Un caisson de ventilation double-ouïe à variation de débit (VFD intégré) est sélectionné pour :",choices:["Uniquement les installations résidentielles simples","Adapter le débit d'air aux besoins réels (occupation, CO₂, HR) → économies d'énergie (P ∝ N³) et meilleur confort","Maximiser le débit constant en toutes circonstances","Minimiser le coût d'installation sans critère de performance"],answer:1,diff:2,explication:"Caisson VMC avec VFD : variation continue du débit selon la demande (occupation, qualité de l'air, heure). Économies par rapport à débit constant : jusqu'à 70% sur la consommation du ventilateur (loi cubique). Régulation via capteurs CO₂ (mesure indirecte de l'occupation) ou hygrostats. Idéal en ERP tertiaire.",tags:["Caisson ventilation","VFD","Variation de débit","Économie d'énergie"]},
  {id:"fed_av12",prompt:"L'essai de débit d'une installation aéraulique (mesure du débit aux bouches) utilise :",choices:["Un wattmètre de puissance","Un anémomètre à fil chaud, un anémomètre à hélice ou un caisson de mesure de débit (Capture Hood) directement positionné sur la bouche de soufflage ou d'extraction","Un tachymètre rotatif","Un thermomètre infrarouge"],answer:1,diff:2,explication:"Équilibrage aéraulique : mesure des débits aux bouches avec caisson (capture hood = mesure directe du débit en m³/h) ou anémomètre à fil chaud/hélice × section du conduit. Comparaison avec débits réglementaires (arrêté 1982/DTU 68.3). Ajustement par registres d'équilibrage. Procès-verbal de réception de l'installation.",tags:["Mesure de débit","Capture Hood","Équilibrage aéraulique","VMC"]},
];

// ─── BANQUE QB_FED_HYDRAULIQUE ───
export const QB_FED_HYDRAULIQUE = [
  {id:"fed_hy1",prompt:"Une pompe centrifuge est sélectionnée en fonction de :",choices:["Uniquement sa puissance nominale","Son point de fonctionnement = intersection entre sa courbe caractéristique (HMT / débit) et la courbe de réseau (pertes de charge / débit)","Sa couleur et ses dimensions","Son fabricant uniquement"],answer:1,diff:2,explication:"Sélection pompe : courbe caractéristique pompe (HMT en fonction de Q) + courbe de réseau (ΔP ∝ Q² pour un réseau à vanne fixe). Le point d'intersection = point de fonctionnement. Si la pompe fonctionne loin de son point nominal BEP (Best Efficiency Point) → rendement faible + surchauffe.",tags:["Pompe centrifuge","Courbe caractéristique","Point de fonctionnement","Hydraulique"]},
  {id:"fed_hy2",prompt:"La HMT (Hauteur Manométrique Totale) d'une pompe comprend :",choices:["Uniquement la hauteur géométrique à vaincre","La somme de la hauteur géométrique (ou pression statique), des pertes de charge régulières et singulières, et de la différence de pression dynamique entre aspiration et refoulement","Le débit multiplié par la pression","La puissance absorbée par le moteur"],answer:1,diff:2,explication:"HMT = Hgéom + ΔP_charge_totale + ΔP_dynamique. Pour un circuit fermé (chauffage en boucle) : HMT = uniquement les pertes de charge du circuit (pas de hauteur statique → pression compensée). Pour circuit ouvert (eau à un réservoir surélevé) : HMT inclut la hauteur géométrique.",tags:["HMT","Pompe","Pertes de charge","Circuit hydraulique"]},
  {id:"fed_hy3",prompt:"Un vase d'expansion (à membrane) dans un circuit de chauffage est dimensionné pour :",choices:["Stocker l'eau chaude sanitaire","Absorber la dilatation de l'eau lors du chauffage (l'eau se dilate de ≈ 4.3% entre 10°C et 90°C) sans dépasser la pression de tarage de la soupape de sécurité","Réguler la pression de l'eau de refroidissement uniquement","Créer une séparation hydraulique entre deux circuits"],answer:1,diff:2,explication:"Dilatation de l'eau : 10°C → 90°C ≈ +4.3% de volume. Sans vase d'expansion : pression monte → soupape de sécurité s'ouvre. Vase à membrane : la pression du gaz (azote) au-dessus de la membrane absorbe la dilatation. Pression de gonflage = pression statique du circuit. Volume vase calculé selon la formule EN 12828.",tags:["Vase d'expansion","Dilatation","Circuit chauffage","Pression"]},
  {id:"fed_hy4",prompt:"Un plancher chauffant hydraulique (PCH) fonctionne en basse température car :",choices:["Les tubes sont trop fins pour les hautes pressions","La surface radiante importante (toute la surface du sol) permet un delta T faible (30-45°C) pour la même puissance qu'un radiateur haute température","Le béton de la dalle ne supporte pas les hautes températures","Les régulateurs imposent 30°C maximum"],answer:1,diff:1,explication:"Plancher chauffant (PCH) : tubes PER ou multicouche noyés dans la chape. Surface émettrice = toute la surface du sol → puissance surfacique faible → T° eau basse (départ 35-45°C, retour 28-35°C). Idéal pour PAC (COP élevé à faible T°). Inertie forte → régulation anticipée. Pas compatible radiateurs haute température sans mélange.",tags:["Plancher chauffant","Basse température","PAC","Inertie"],},
  {id:"fed_hy5",prompt:"Un déséquilibre hydraulique dans un réseau de chauffage entraîne :",choices:["Uniquement une surconsommation d'énergie mineure","Des radiateurs trop chauds sur les circuits courts et trop froids sur les circuits longs → inconfort et surconsommation","Une pression uniforme dans tous les émetteurs","Un meilleur rendement des pompes"],answer:1,diff:2,explication:"Déséquilibre hydraulique : les courts-circuits (résistances faibles) captent trop de débit au détriment des circuits longs. Solution : équilibrage par vannes régulatrices de débit (STAD, STAF), robinets d'équilibrage sur chaque départ, ou pompes à débit variable avec régulation de pression différentielle. Équilibrage = prérequis énergétique.",tags:["Équilibrage hydraulique","Réseau chauffage","Débit","Radiateurs"]},
  {id:"fed_hy6",prompt:"La séparation hydraulique par un échangeur à plaques entre un circuit primaire (PAC/chaudière) et un circuit secondaire (distribution) permet :",choices:["D'augmenter la pression du circuit secondaire","D'isoler hydrauliquement les deux circuits (pression, débit, qualité d'eau différents) tout en transférant l'énergie thermique","De supprimer le besoin de pompe dans le circuit secondaire","D'éviter l'utilisation d'un vase d'expansion"],answer:1,diff:2,explication:"Échangeur de chaleur à plaques (ECP) : séparation physique des circuits (pas de mélange d'eau). Transfert thermique efficace (surface d'échange importante par volume réduit). Utilisé quand les pressions/qualités d'eau sont différentes (circuit PAC glycolé ↔ circuit chauffage eau), ou pour protéger les équipements (sous-station de chauffage urbain).",tags:["Échangeur à plaques","Séparation hydraulique","Circuit primaire/secondaire","ECP"]},
  {id:"fed_hy7",prompt:"L'eau chaude sanitaire (ECS) en réseau collectif doit être maintenue à :",choices:["40°C (confort sans risque de brûlure)","≥ 60°C en production et ≥ 50°C en tout point du réseau pour prévenir la légionellose (Legionella pneumophila)","30°C pour économiser l'énergie","55°C en production et 45°C en distribution uniquement en été"],answer:1,diff:2,explication:"Réglementation ECS collective (arrêté du 30/11/2005) : T° production ≥ 60°C (stérilisation Legionella), T° distribution ≥ 50°C en tout point. Legionella prolifère entre 25-45°C et meurt à ≥ 55°C (rapide à 60°C). Mitigeur thermostatique anti-brûlure ≤ 50°C en sortie au point de puisage. Relevé thermique mensuel obligatoire.",tags:["ECS","Légionellose","Legionella","Réglementation","Température"]},
  {id:"fed_hy8",prompt:"Le dimensionnement d'un réseau de distribution d'eau froide utilise la méthode des Unités de Charge (UC) selon :",choices:["L'arrêté du 24 mars 1982","La norme NF EN 806 / DTU 60.11 : chaque appareil a des UC selon son débit de pointe → calcul du débit simultané (simultanéité)","La RE 2020 uniquement","La loi de Poiseuille directement sans coefficient de simultanéité"],answer:1,diff:2,explication:"DTU 60.11 / NF EN 806-3 : méthode des UC (Unités de Charge) pour tenir compte de la diversité d'usage (les appareils ne fonctionnent pas tous en même temps). UC attribués par type d'appareil. Débit simultané Q = f(ΣUC). Vitesse max dans les canalisations : 0.5-1 m/s (distribution), 2-3 m/s (colonnes montantes). Pertes de charge < 30 Pa/m.",tags:["DTU 60.11","Unités de charge","Simultanéité","EF/ECS"]},
  {id:"fed_hy9",prompt:"Une vanne 3 voies mélangeuse dans un circuit de chauffage est utilisée pour :",choices:["Couper complètement le débit dans le circuit","Mélanger l'eau chaude primaire avec l'eau de retour secondaire refroidie pour obtenir une T° de départ modulée (régulation de la courbe de chauffe)","Mesurer le débit dans la canalisation","Compenser la pression différentielle du réseau"],answer:1,diff:2,explication:"Vanne 3 voies mélangeuse (M) : mélange eau chaude (C) + eau de retour (R) → eau de départ (D) à température régulée. Actionneur motorisé piloté par régulateur selon T_ext (courbe de chauffe) ou T_retour. Vanne 3 voies déviante (D) : dérive le débit vers deux circuits. La courbe de chauffe = loi d'eau (T_départ = f(T_ext)).",tags:["Vanne 3 voies","Régulation","Courbe de chauffe","Circuit chauffage"]},
  {id:"fed_hy10",prompt:"Le robinet thermostatique (robinet de radiateur) régule :",choices:["Le débit global de la pompe","La température locale dans la pièce en modulant le débit d'eau dans ce radiateur (valve thermostatique + tête thermostatique avec capteur de cire)","La pression du réseau général","Le débit de retour dans le collecteur principal"],answer:1,diff:1,explication:"Robinet thermostatique : corps de vanne (préréglable pour équilibrage) + tête thermostatique (capteur cire dilatant → ferme la vanne si T° pièce atteint la consigne). Régulation pièce par pièce sans électricité (mécanique). Préréglage = équilibrage. Remplacement par robinet programmable (électronique) pour économies supplémentaires.",tags:["Robinet thermostatique","Radiateur","Régulation","Équilibrage"]},
  {id:"fed_hy11",prompt:"Le rendement global d'un réseau de distribution de chaleur (pertes en réseau) est caractérisé par :",choices:["Le ratio puissance fournie aux émetteurs / puissance produite en chaudière (pertes linéiques des canalisations non isolées)","Le facteur de puissance électrique de la pompe","La pression différentielle entre départ et retour","Le débit de la pompe en m³/h uniquement"],answer:1,diff:2,explication:"Pertes de réseau : les canalisations de distribution perdent de la chaleur vers l'extérieur si elles ne sont pas isolées (ou si elles traversent des locaux non chauffés). Pertes réseau : ΦR = U_canalisation × L × (T_eau - T_ext). DTU 45.11 / réglementation RT2012 imposent des épaisseurs d'isolation minimales selon le diamètre et le type de réseau.",tags:["Réseau chauffage","Pertes en réseau","Isolation canalisations","DTU 45.11"]},
  {id:"fed_hy12",prompt:"Le coefficient de performance (COP) d'un système de chauffage urbain (réseau de chaleur) est qualifié par :",choices:["Uniquement la T° de l'eau primaire en sous-station","Le contenu CO₂ et énergies primaires du mix énergétique du réseau (biomasse, géothermie, récupération → facteur EnR&R)","La pression de service du réseau primaire","La distance entre la chaufferie et les abonnés"],answer:1,diff:3,explication:"Réseaux de chaleur urbains (RCU) : alimentation en eau chaude haute pression (70-120°C) depuis des chaufferies centrales (bois-énergie, géothermie, récupération chaleur fatale, cogénération). Facteur EnR&R (Énergie Renouvelable et de Récupération) ≥ 50% → éligibilité aux aides (Fonds Chaleur ADEME) et coefficient d'énergie primaire favorable (1.0).",tags:["Réseau de chaleur","EnR&R","Géothermie","Cogénération"]},
];

// ─── BANQUE QB_FED_FROID_CLIM ───
export const QB_FED_FROID_CLIM = [
  {id:"fed_fc1",prompt:"Le diagramme de Mollier (enthalpie/pression) du cycle frigorifique permet de lire :",choices:["La vitesse du compresseur en tr/min","Les enthalpies à chaque point du cycle (h1, h2, h3, h4) → puissances frigorifique et calorifique, travail du compresseur, COP"],answer:1,diff:2,explication:"Diagramme h-log(P) (Mollier) : abscisse = enthalpie massique h (kJ/kg), ordonnée = pression (bar). Points clés : 1 (sortie évaporateur), 2 (sortie compresseur), 3 (sortie condenseur), 4 (sortie détendeur). Puissance frig = ṁ × (h1-h4), puissance cal = ṁ × (h2-h3), W_compresseur = ṁ × (h2-h1). COP = (h1-h4)/(h2-h1).",tags:["Mollier","Diagramme","Cycle frigorifique","Enthalpie"]},
  {id:"fed_fc2",prompt:"La surchauffe à l'aspiration du compresseur (gaz chauds) est volontairement maintenue pour :",choices:["Augmenter le COP en refroidissant le gaz","Éviter que des gouttelettes de liquide n'entrent dans le compresseur (coup de liquide → destruction)","Réduire la pression d'aspiration","Augmenter le débit massique du fluide"],answer:1,diff:2,explication:"Surchauffe (5-10°C) : le fluide frigorigène en sortie d'évaporateur est légèrement en phase gazeuse surchauffée → garantit l'absence de liquide à l'aspiration du compresseur. Le liquide est incompressible → coup de liquide = destruction instantanée du compresseur. Sous-refroidissement (5-10°C) au condenseur améliore le COP.",tags:["Surchauffe","Compresseur","Coup de liquide","Cycle frigorifique"]},
  {id:"fed_fc3",prompt:"L'EER (Energy Efficiency Ratio) d'une unité de climatisation est défini par :",choices:["EER = P_chaud / P_élec (comme le COP en chauffe)","EER = P_froid / P_élec (puissance frigorifique utile / puissance électrique consommée en mode refroidissement)","EER = T_évaporateur / T_condenseur","EER = Débit air / Puissance électrique"],answer:1,diff:1,explication:"EER = Energy Efficiency Ratio (mode refroidissement). EER de 3 : pour 1 kW électrique, 3 kW de puissance frigorifique. SEER = EER saisonnier (conditions réelles sur la saison de refroidissement). Réglementation ErP : SEER minimum imposé selon la puissance de l'unité. PAC réversible : COP en chauffe > EER (condensation à T_int plus élevée).",tags:["EER","SEER","Climatisation","Performance"]},
  {id:"fed_fc4",prompt:"La réglementation F-gas (UE 517/2014, révisée 2024) impose aux techniciens travaillant sur des équipements contenant des HFC de :",choices:["Uniquement enregistrer les interventions","Posséder une attestation de capacité (catégorie I à IV selon la charge en GWP) délivrée par un organisme agréé (DEKRA, Bureau Veritas, etc.)","Utiliser uniquement du R290 (propane)","Acheter leurs fluides uniquement auprès du fabricant de l'équipement"],answer:1,diff:2,explication:"Attestation de capacité F-gas : catégorie I (toutes interventions, y.c. récupération), II (installation sans récupération), III (contrôle étanchéité sans récupération), IV (récupération seule). Attestation délivrée après examen (organisme accrédité). Registres de l'installation obligatoires (interventions, charges). Récupération des fluides obligatoire en fin de vie.",tags:["F-gas","Attestation de capacité","HFC","Réglementation"]},
  {id:"fed_fc5",prompt:"Le contrôle périodique d'étanchéité d'une installation frigorifique (charge > 5 t éq. CO₂) doit être réalisé :",choices:["Tous les 5 ans uniquement","Tous les 12 mois (charge 5-50 t éq. CO₂) ou tous les 6 mois (> 50 t éq. CO₂) par un technicien certifié F-gas"],answer:1,diff:2,explication:"Règlement F-gas UE 517/2014 : seuils de contrôle basés sur la charge en tonnes éq. CO₂ (masse (kg) × PRG). < 5 t éq. CO₂ : pas de contrôle périodique obligatoire. 5-50 t : contrôle annuel. > 50 t : contrôle semestriel. > 500 t : + détecteur de fuite automatique. Registre d'installation obligatoire.",tags:["Contrôle étanchéité","F-gas","Charges","Registre"]},
  {id:"fed_fc6",prompt:"Le fluide frigorigène R290 (propane) est dit 'naturel' car :",choices:["Il est produit industriellement sans pétrole","Son PRG = 3 (quasi nul, pas d'impact sur le réchauffement climatique) et c'est un hydrocarbure naturel — mais il est hautement inflammable (A3)"],answer:1,diff:2,explication:"Fluides naturels : R290 (propane, PRG=3, A3 inflammable), R600a (isobutane, PRG=3, A3), R744 (CO₂, PRG=1, A1), R717 (ammoniac NH₃, PRG=0, B2L toxique-inflammable). Alternatives aux HFC (R32 PRG=675, R134a PRG=1430). Tendance réglementaire : transition vers fluides bas-PRG. Charge réduite (< 3 kg R290 recommandé pour sécurité).",tags:["R290","Propane","Fluide naturel","PRG","Inflammable"]},
  {id:"fed_fc7",prompt:"Un système DRV (Débit de Réfrigérant Variable, ou VRF) se distingue d'un système split classique par :",choices:["L'utilisation d'un seul fluide frigorigène spécifique","La gestion centralisée de plusieurs unités intérieures (jusqu'à 64) par une seule unité extérieure, avec variation du débit de frigorigène selon la charge de chaque pièce"],answer:1,diff:2,explication:"DRV/VRF (Variable Refrigerant Flow) : une unité extérieure + réseau de frigorène (R410A ou R32) + multiples unités intérieures. Chaque unité intérieure module sa puissance indépendamment. Détendeurs électroniques individuels. Possibilité de récupération de chaleur (certaines pièces en chauffe, d'autres en froid simultanément). Usage tertiaire (bureaux, hôtels, commerces).",tags:["DRV","VRF","Climatisation","Tertiaire"]},
  {id:"fed_fc8",prompt:"La tour aéroréfrigérante (TAR) dans un système de refroidissement tertiaire sert à :",choices:["Produire de l'eau glacée directement","Dissiper la chaleur du condenseur par évaporation d'une partie de l'eau (condensation humide), avec un meilleur rendement qu'un condenseur à air"],answer:1,diff:2,explication:"Tour aéroréfrigérante (cooling tower) : eau de condensation circulant dans le condenseur du chiller → pompée vers la tour → pulvérisée sur des garnissages → évaporation partielle → dissipation de chaleur. T° eau froide ≈ 27-32°C (contre 35-45°C pour condenseur à air). Meilleur COP du chiller. Risque légionellose → entretien strict (arrêté du 14/12/2013).",tags:["Tour aéroréfrigérante","TAR","Condenseur","Légionellose"]},
  {id:"fed_fc9",prompt:"Le TEWI (Total Equivalent Warming Impact) d'une installation frigorifique prend en compte :",choices:["Uniquement les fuites de fluide frigorigène","Les émissions directes (fuites du fluide frigorigène × PRG) ET indirectes (CO₂ lié à la consommation électrique sur la durée de vie)"],answer:1,diff:3,explication:"TEWI = impact climatique total = effet direct (fuites fluide × PRG × kg fuite × années) + effet indirect (consommation électrique × facteur CO₂ du réseau × durée de vie). Un fluide à faible PRG (R290) mais consommant plus d'électricité peut avoir un TEWI similaire à un fluide plus efficace à PRG plus élevé. Raisonnement global.",tags:["TEWI","Impact climatique","PRG","Efficacité"]},
  {id:"fed_fc10",prompt:"La réversibilité d'une PAC ou d'un climatiseur (mode chauffe/froid) est assurée par :",choices:["Deux compresseurs distincts","Un inverseur de cycle (vanne 4 voies) qui inverse la circulation du frigorigène → l'évaporateur devient condenseur et inversement"],answer:1,diff:2,explication:"Vanne 4 voies (reversing valve) : commute entre mode chauffe (condenseur côté intérieur = chaleur fournie) et mode froid (évaporateur côté intérieur = fraîcheur fournie). L'unité extérieure alterne entre condenseur (mode froid) et évaporateur (mode chaud). Actionnée par solénoïde. Standard sur toutes les PAC air/air réversibles.",tags:["Réversibilité","Vanne 4 voies","PAC","Mode chauffe/froid"]},
  {id:"fed_fc11",prompt:"Un système de free cooling adiabatique (vs refroidissement mécanique) en data center peut économiser :",choices:["5-10% de l'énergie de refroidissement","60-80% de l'énergie de refroidissement lors des périodes où T_ext < T_eau_froide_requise"],answer:1,diff:3,explication:"Free cooling (économiseur) : lorsque T_ext < T° souhaitée de l'eau froide (< 12°C environ), on utilise directement l'air extérieur pour refroidir sans compresseur. Économiseur à circuit direct ou indirect (échangeur). Data centers en Europe du Nord : 80-90% du temps en free cooling. PUE (Power Usage Effectiveness) = énergie totale / énergie IT.",tags:["Free cooling","Data center","Économie d'énergie","Adiabatique"]},
  {id:"fed_fc12",prompt:"La température de claquage (température de dewpoint ou point de rosée) dans un local climé permet de :",choices:["Régler la température de consigne du thermostat","Calculer la T° à laquelle l'air se sature (HR = 100%) → risque de condensation sur les surfaces froides (batterie froide, gaines, façades non isolées)"],answer:1,diff:2,explication:"Point de rosée (Td) : T° à partir de laquelle l'air se condense (en dessous → condensation). Exemple : air à 25°C / HR 60% → Td ≈ 17°C. Si surface < 17°C → condensation. Importance en CTA (température batterie froide > Td pour éviter condensation excessive) et isolation des gaines froides en milieu humide.",tags:["Point de rosée","Condensation","HR","Psychrométrie"]},
];

// ─── BANQUE QB_FED_ENR ───
export const QB_FED_ENR = [
  {id:"fed_enr1",prompt:"Le rendement d'un capteur solaire plan (CSP) en eau chaude sanitaire solaire est typiquement de :",choices:["5-10% (comme un panneau PV)","40-70% selon les conditions (température, ensoleillement) — bien supérieur au PV en production thermique","95-100% (quasi total)","25-30% uniquement"],answer:1,diff:2,explication:"Capteur solaire plan (thermique) : rendement η = 0 - a1×(T*) - a2×G×(T*)² (courbe EN ISO 9806). T* = (T_moy - T_amb)/G. Typiquement 50-70% à faible ΔT (eau froide + fort ensoleillement). Capteurs à tubes sous vide (CPC) : η > 65% même à faible ensoleillement. CESI (Chauffe-Eau Solaire Individuel) : taux de couverture 50-70%.",tags:["Solaire thermique","CESI","Rendement capteur","CPC"]},
  {id:"fed_enr2",prompt:"Pour un panneau solaire photovoltaïque (PV) standard silicium cristallin, le rendement est approximativement de :",choices:["5% (inefficace)","18-22% (silicium monocristallin), soit 150-200 Wc/m²","50% (très haute efficacité)","35% (cellules bifaciales uniquement)"],answer:1,diff:1,explication:"Silicium monocristallin : η ≈ 18-22%, Wc ≈ 200-220 Wc/m². Polycristallin : η ≈ 15-18%. Amorphe (thin film) : 7-12%. Haute efficacité HJT/TOPCon : 22-24%. Rendement chuté avec T° : -0.4%/°C au-delà de 25°C (NOCT). Performance simulée via logiciels (PVsyst, HelioScope).",tags:["Photovoltaïque","Rendement","Silicium","PV"]},
  {id:"fed_enr3",prompt:"L'onduleur (inverter) dans une installation PV a pour rôle :",choices:["Stocker l'énergie solaire en journée","Convertir le courant continu (DC) produit par les panneaux en courant alternatif (AC) synchronisé avec le réseau (50 Hz, 230 V ou 400 V)","Mesurer uniquement la puissance des panneaux","Réguler la charge des batteries uniquement"],answer:1,diff:1,explication:"Onduleur PV : DC → AC (MPPT = Maximum Power Point Tracking pour optimiser la puissance extraite des panneaux). Onduleur central (un seul), onduleurs de chaîne (string inverters), microonduleurs (un par panneau). Efficacité > 97%. Connecté au réseau ou avec batterie (hybride). En cas de coupure réseau → îlotage interdit (sécurité ENEDIS).",tags:["Onduleur","PV","MPPT","DC/AC"]},
  {id:"fed_enr4",prompt:"La géothermie très basse énergie (sondes verticales, PAC eau/eau) exploite la stabilité thermique du sol à :",choices:["0°C en profondeur (réseau de froid naturel)","10-15°C toute l'année à partir de 15-20 m de profondeur, quelle que soit la saison","30°C en été et 5°C en hiver","La T° varie de la même façon qu'en surface"],answer:1,diff:1,explication:"Géothermie très basse énergie (< 30°C) : sondes verticales (50-200 m) ou capteurs horizontaux (0.8-1.2 m de profondeur). Sol ≈ 12-15°C toute l'année → source froide stable pour PAC (COP de 4-5 vs 2-3 pour PAC air/air). Sonde géothermique : tube en U ou coaxial avec fluide caloporteur (eau glycolée). Forage soumis à déclaration ou autorisation selon profondeur.",tags:["Géothermie","Sonde géothermique","Stabilité thermique","PAC eau/eau"]},
  {id:"fed_enr5",prompt:"Le contrat d'autoconsommation collective PV (REACo) permet à des producteurs et consommateurs locaux de :",choices:["Revendre toute leur production à EDF OA","Partager l'énergie solaire produite entre plusieurs consommateurs d'un même périmètre géographique via le réseau de distribution (virtualisation des échanges)","Créer un réseau privé indépendant d'ENEDIS","Obtenir des subventions automatiques de l'ADEME"],answer:1,diff:3,explication:"Autoconsommation collective (loi transition énergétique 2017) : producteurs + consommateurs proches (même poste HTB → BT, rayon max depuis 2023 = variable selon décret). Répartition de la production selon des clés définies dans l'opération. Économies sur la facture, valorisation de la production locale. Gestion via opérateur de l'opération (OOA).",tags:["Autoconsommation collective","PV","REACo","Réseau de distribution"]},
  {id:"fed_enr6",prompt:"Un chauffe-eau thermodynamique (CET) utilise :",choices:["Uniquement une résistance électrique (comme un chauffe-eau classique)","Une PAC air/air intégrée pour produire l'ECS : extrait la chaleur de l'air ambiant ou de l'air extérieur pour chauffer l'eau (COP ≈ 3)","L'énergie solaire par des panneaux thermiques sur le toit","La géothermie via des capteurs enterrés"],answer:1,diff:1,explication:"CET (Chauffe-Eau Thermodynamique) : petite PAC intégrée dans le ballon d'ECS. Évaporateur prélève chaleur de l'air (ambiant ou extrait/extérieur). COP ≈ 2.5-3.5. Consomme 3× moins qu'un chauffe-eau électrique à résistance. Éligible au crédit d'impôt et aux aides ANAH. Nuisance sonore possible si installation en espace de vie.",tags:["CET","Chauffe-eau thermodynamique","PAC","ECS"]},
  {id:"fed_enr7",prompt:"Le Fonds Chaleur de l'ADEME finance des projets d'énergies renouvelables thermiques (biomasse, géothermie, solaire thermique) à destination des :",choices:["Particuliers uniquement pour leur résidence principale","Collectivités, entreprises et bailleurs sociaux pour des projets > 100 MWh/an","Tout le monde sans condition de taille","Exclusivement les réseaux de chaleur en zone rurale"],answer:1,diff:2,explication:"Fonds Chaleur ADEME : depuis 2009, subventionne les projets ENR thermiques dans le tertiaire, l'industrie, l'agriculture et les réseaux de chaleur. Objectif : développer la chaleur renouvelable (biomasse, géothermie, solaire thermique, PAC de grande puissance). Budget ~600 M€/an. Critère clé : coût de la chaleur produite vs énergie fossile de référence.",tags:["Fonds Chaleur","ADEME","ENR thermique","Subvention"]},
  {id:"fed_enr8",prompt:"La puissance crête (Wc) d'un panneau PV est mesurée dans les conditions standard (STC) :",choices:["Ensoleillement = 500 W/m², T° cellule = 20°C, masse d'air AM 1.0","Ensoleillement = 1000 W/m², T° cellule = 25°C, spectre AM 1.5","Ensoleillement = 1200 W/m², T° ambiante = 30°C","En plein soleil estival en France"],answer:1,diff:2,explication:"STC (Standard Test Conditions) : G = 1000 W/m², T_cellule = 25°C, spectre solaire AM 1.5 (masse d'air correspondant à un angle de 48.2°). Conditions normalisées pour comparaison entre fabricants. En conditions NOCT (45°C, 800 W/m²) la puissance est ≈ 10% inférieure. En usage réel (pertes câbles, salissures, ombrage, T° haute) → facteur de performance PR (Performance Ratio) ≈ 75-85%.",tags:["STC","Wc","Conditions standard","PV"]},
  {id:"fed_enr9",prompt:"La biomasse énergie (bois, pellets, résidus agricoles) est considérée comme énergie renouvelable car :",choices:["Elle ne produit pas de CO₂ lors de la combustion","Le CO₂ émis lors de la combustion est reabsorbé par la croissance des forêts sur le long terme (bilan carbone quasi neutre si gestion durable)","Elle est inépuisable comme le soleil","Sa combustion ne produit ni suies ni particules fines"],answer:1,diff:1,explication:"Biomasse énergie = cycle carbone court : la plante absorbe CO₂ pendant sa croissance → libéré lors de la combustion → réabsorbé par nouvelles plantations. Bilan CO₂ quasi nul si gestion forestière durable. Attention : émissions de particules fines (PM2.5, PM10) → chaudières à haute efficacité + filtres recommandés. Énergie primaire : coefficient 0.6 en RE 2020.",tags:["Biomasse","Bois-énergie","Carbone renouvelable","Forêt"]},
  {id:"fed_enr10",prompt:"La production éolienne varie avec la vitesse du vent selon :",choices:["Puissance ∝ v (linéaire)","Puissance ∝ v³ (cubique) : doubler la vitesse du vent octuple la puissance disponible","Puissance ∝ v² (quadratique)","Puissance constante quelle que soit la vitesse du vent"],answer:1,diff:2,explication:"Puissance éolienne : P = ½ × ρ × A × Cp × v³. Cp = coefficient de Betz (max théorique = 0.593). A = surface du rotor. v = vitesse du vent. La dépendance en v³ explique pourquoi l'implantation est cruciale (vent de 10 m/s → 8× plus d'énergie qu'à 5 m/s). Vitesse de démarrage ≈ 3-4 m/s, puissance nominale ≈ 12-14 m/s, coupure ≈ 25 m/s.",tags:["Éolien","Loi cubique","Betz","Puissance"]},
  {id:"fed_enr11",prompt:"Le certificat de qualification RGE (Reconnu Garant de l'Environnement) est obligatoire pour :",choices:["Tout artisan qui pose des fenêtres","Les artisans et entreprises dont les clients souhaitent bénéficier des aides fiscales (MaPrimeRénov', CEE) pour des travaux d'économies d'énergie ou d'installations EnR"],answer:1,diff:1,explication:"RGE : certification qualité pour accéder aux aides de l'État liées à la rénovation énergétique (MaPrimeRénov', éco-PTZ, CEE). Qualification par organisme accrédité (Qualibat, Qualifelec, QualiPAC, Qualit'EnR). Valable 4 ans, avec audit sur chantier. Obligatoire pour l'entreprise qui réalise les travaux (pas le donneur d'ordre).",tags:["RGE","Certification","MaPrimeRénov","Aides fiscales"]},
  {id:"fed_enr12",prompt:"L'indice de productivité d'un parc solaire PV (kWh/kWc/an) moyen en France métropolitaine est de :",choices:["200-300 kWh/kWc/an (très faible rayonnement)","900-1400 kWh/kWc/an selon la localisation (Sud : 1300-1400 ; Nord : 900-1000)","2000-2500 kWh/kWc/an (comme les tropiques)","400-500 kWh/kWc/an (France entière uniforme)"],answer:1,diff:2,explication:"Productivité PV (index de performance) : dépend de l'ensoleillement, de l'orientation (sud optimal), de l'inclinaison (30-35° pour maximiser en France), des pertes (température, ombrage, câbles). Marseille ≈ 1300-1400 kWh/kWc/an, Paris ≈ 1000, Rennes ≈ 950. Logiciel PVsyst ou HelioScope calcule la production annuelle estimée.",tags:["Productivité PV","kWh/kWc","Ensoleillement","France"]},
];

// ─── BANQUE QB_FED_REGLEMENTATION ───
export const QB_FED_REGLEMENTATION = [
  {id:"fed_reg1",prompt:"La RE 2020 succède à la RT 2012 et s'applique aux permis de construire déposés depuis :",choices:["Janvier 2018","Janvier 2022 pour les maisons individuelles et logements collectifs (tertiaire neuf en cours de déploiement progressif)","Juillet 2025 uniquement","Janvier 2015"],answer:1,diff:1,explication:"RE 2020 (Réglementation Environnementale 2020) : applicable aux logements neufs depuis le 1er janvier 2022 (maisons individuelles et immeubles collectifs), puis progressivement au tertiaire. Elle renforce la RT 2012 en ajoutant un troisième pilier : l'impact carbone (analyse de cycle de vie ACV du bâtiment). Révision des seuils prévue en 2025 et 2028.",tags:["RE 2020","RT 2012","Application","Bâtiment neuf"]},
  {id:"fed_reg2",prompt:"Le label BBC Effinergie Rénovation (Bâtiment Basse Consommation) exige une consommation d'énergie primaire inférieure à :",choices:["100 kWh/m²/an en rénovation","80 kWh/m²/an × coefficient climatique (Cep ≤ 80 kWh/m²/an × modulation géographique et altitude)","50 kWh/m²/an (standard BEPOS)","150 kWh/m²/an (critère minimal)"],answer:1,diff:2,explication:"BBC Rénovation (Effinergie) : Cep ≤ 80 kWh/m²/an × coefficient Ccoef (module selon la zone climatique, de 1.0 à 1.3 selon altitude/région) + perméabilité à l'air testée. Plus exigeant que la RT 2012 (100 kWh/m²/an pour le neuf). Condition obligatoire pour certaines aides (éco-PTZ, MaPrimeRénov' Rénovation Globale).",tags:["BBC Effinergie","Rénovation","80 kWh","Cep"]},
  {id:"fed_reg3",prompt:"L'arrêté du 3 mai 2007 (installations d'eau chaude sanitaire collective) impose une surveillance pour prévenir :",choices:["Les problèmes de pression dans les réseaux","Le risque légionellose dans les réseaux d'ECS collectifs (T° maintenance, purges, nettoyage, analyses bactériologiques)","Les pertes thermiques des canalisations","La corrosion des tuyaux en cuivre"],answer:1,diff:2,explication:"Arrêté du 3 mai 2007 (révisé) : applicable aux ERP (établissements recevant du public) avec réseau ECS collectif. Impose : T° production ≥ 60°C, T° distribution ≥ 50°C en tous points, purges régulières des points bas, maintenance, analyses bactériologiques si risque. Plan de maîtrise du risque légionellose (carnet sanitaire).",tags:["ECS collective","Légionellose","Arrêté 2007","Réglementation"]},
  {id:"fed_reg4",prompt:"Les Certificats d'Économies d'Énergie (CEE) obligent :",choices:["Les ménages à financer eux-mêmes les travaux de rénovation","Les fournisseurs d'énergie (obligés) à financer des économies d'énergie auprès des particuliers et entreprises (financement des travaux via 'coups de pouce')","Les constructeurs de bâtiments neufs à installer des ENR","L'État à verser des subventions directes aux artisans RGE"],answer:1,diff:2,explication:"CEE (système obligatoire depuis 2006) : les fournisseurs d'énergie (EDF, Engie, TotalEnergies...) ont des obligations de réduction de la consommation chez leurs clients. Ils financent des travaux éligibles (isolation, PAC, chaudière biomasse, éclairage LED...) en échange de certificats. Coups de pouce : bonifications pour les opérations prioritaires (isolation, chauffage). Les CEE peuvent aussi être revendus.",tags:["CEE","Certificats d'économies d'énergie","Obligés","Rénovation"]},
  {id:"fed_reg5",prompt:"La réglementation acoustique des bâtiments neufs (arrêté du 30 juin 1999, modifié 2013) impose un isolement DnT,A entre deux logements de :",choices:["25 dB minimum","≥ 53 dB entre logements (bruits aériens) dans les bâtiments d'habitation collectifs","60 dB minimum (standard hôtelier)","40 dB uniquement pour les murs séparatifs en briques"],answer:1,diff:2,explication:"Réglementation acoustique (NF S 31-130) : DnT,A ≥ 53 dB entre logements (bruits aériens). Niveau de bruit de choc Ln,AT ≤ 58 dB. Bruits des équipements : ≤ 35 dB(A) en séjour. NRA (Nouvelle Réglementation Acoustique) 2000 pour les logements neufs. Label Qualitel acoustique pour dépasser les minima réglementaires.",tags:["Acoustique","DnT,A","NRA","Logement collectif"]},
  {id:"fed_reg6",prompt:"Le DTU (Document Technique Unifié) est :",choices:["Un décret gouvernemental ayant force de loi","Un document normatif de référence (norme NF) définissant les règles de l'art pour chaque corps de métier du bâtiment (plomberie, isolation, électricité...)","Un label de performance énergétique","Un document d'inspection de chantier obligatoire"],answer:1,diff:1,explication:"DTU : normes de référence pour la mise en œuvre des ouvrages dans le BTP. Exemples : DTU 60.1 (plomberie sanitaire), DTU 68.3 (VMC), DTU 45.11 (isolation des réseaux de chaleur/froid). Deviennent des normes NF (NF DTU xxx). En cas de litige, le respect du DTU est une preuve du respect des règles de l'art. Les DTU sont publiés par l'AFNOR.",tags:["DTU","Normes","Règles de l'art","BTP"]},
  {id:"fed_reg7",prompt:"Le contrôle des installations électriques par le CONSUEL est obligatoire avant :",choices:["Chaque entretien annuel","La mise en service d'une installation neuve ou rénovée (attestation de conformité permettant la mise en service par ENEDIS)","La vente d'un bien immobilier","Tous les 10 ans dans les habitations"],answer:1,diff:2,explication:"CONSUEL (COmité National pour la Sécurité des USagers de l'ELectricité) : organisme agréé par l'État qui contrôle la conformité des installations électriques neuves (et rénovations avec modification du tableau). L'attestation de conformité CONSUEL est indispensable pour qu'ENEDIS raccorde l'installation. Contrôle NF C 15-100.",tags:["CONSUEL","Conformité électrique","ENEDIS","NF C 15-100"]},
  {id:"fed_reg8",prompt:"La norme NF EN 12831 définit la méthode de calcul de :",choices:["La consommation d'eau chaude sanitaire","Les déperditions thermiques des bâtiments (puissance de chauffage de base) selon la méthode européenne harmonisée","Le coefficient U des fenêtres","La résistance au feu des structures"],answer:1,diff:2,explication:"NF EN 12831 (méthode de calcul des déperditions thermiques de base) : remplace les anciennes méthodes nationales (G, K). Calcule la puissance de chauffage de base (W ou kW) nécessaire pour maintenir la T° de consigne à la T° extérieure de base (T_ext de base selon la zone climatique). Base du dimensionnement de l'installation de chauffage.",tags:["NF EN 12831","Déperditions","Puissance chauffage","Calcul thermique"]},
  {id:"fed_reg9",prompt:"Le classement REI des éléments de structure (résistance au feu) signifie :",choices:["Rendement, Efficacité, Isolation (performances thermiques)","R (Résistance mécanique) + E (Étanchéité aux flammes) + I (Isolation thermique) exprimés en minutes (REI 60, REI 120)","Règle, Équipement, Installation","Rayonnement, Émissivité, Isolation"],answer:1,diff:2,explication:"Classement feu (EN 13501-2) : R = stabilité mécanique (ne s'effondre pas), E = étanchéité aux flammes/gaz (pas de propagation), I = isolation thermique (face non exposée reste froide). Exprimés en minutes : REI 30, REI 60, REI 90, REI 120. Planchers : REI 60 standard. Logements collectifs : murs séparatifs REI 60 minimum.",tags:["REI","Résistance au feu","Incendie","Structure"]},
  {id:"fed_reg10",prompt:"La garantie décennale d'un installateur couvre :",choices:["Uniquement les dommages causés par des tempêtes ou inondations","Les dommages compromettant la solidité de l'ouvrage ou le rendant impropre à sa destination, pendant 10 ans après la réception","Les défauts d'entretien du client","Les pannes d'équipements dues à un mauvais usage"],answer:1,diff:1,explication:"Garantie décennale (art. 1792 Code civil) : responsabilité de l'entrepreneur pendant 10 ans pour tout dommage (vice caché, malfaçon) compromettant la solidité ou l'utilisation de l'ouvrage. Assurance dommage-ouvrage (DO) obligatoire pour le maître d'ouvrage. Assurance RCD (Responsabilité Civile Décennale) obligatoire pour tous les constructeurs. Garantie de parfait achèvement : 1 an.",tags:["Garantie décennale","Assurance","Responsabilité","Construction"]},
  {id:"fed_reg11",prompt:"La loi Elan (2018) introduit notamment l'obligation d'accessibilité universelle dans les bâtiments :",choices:["Pour 100% des logements neufs en collectif","Pour 20% des logements neufs en collectif (logements adaptables), avec obligation de réaliser les travaux d'adaptation sur demande du locataire/propriétaire en situation de handicap","Pour tous les logements individuels uniquement","Pour les bâtiments tertiaires de plus de 5000 m²"],answer:1,diff:3,explication:"Loi ELAN (Évolution du Logement, de l'Aménagement et du Numérique, 2018) : dans les immeubles collectifs neufs, 100% des logements doivent être évolutifs (adaptables) et 20% accessibles d'emblée (normes PMR complètes). Elle simplifie aussi les normes de stationnement, de recours contre permis de construire, et introduit le bail mobilité.",tags:["Loi Elan","Accessibilité PMR","Logement collectif","Handicap"]},
  {id:"fed_reg12",prompt:"Le Schéma Directeur de la Transition Énergétique (SDTE) et le Plan Climat-Air-Énergie Territorial (PCAET) sont élaborés par :",choices:["Les bureaux d'études thermiques","Les établissements publics de coopération intercommunale (EPCI) de plus de 20 000 habitants → stratégie locale de réduction des émissions de GES et de développement des ENR","L'ADEME uniquement au niveau national","Les syndicats d'énergie départementaux"],answer:1,diff:3,explication:"PCAET : document de planification locale obligatoire pour les EPCI > 20 000 habitants. Contenu : diagnostic énergie-climat, objectifs (réduction GES, ENR, maîtrise énergie), programme d'actions. Remplace le SRCAE et le PCET. Révisé tous les 6 ans. L'ADEME accompagne l'élaboration. Outil de mise en œuvre de l'Accord de Paris à l'échelle locale.",tags:["PCAET","EPCI","Transition énergétique","Collectivités"]},
];

// ─── BANQUE E5 : INTERVENTION SUR LES SYSTÈMES ───
export const QB_FED_E5_BILAN = [
  {id:"fed_e5_1",prompt:"L'épreuve E5 du BTS FED (Intervention sur les systèmes) dure :",choices:["2 heures (coefficient 3)","4 heures (coefficient 5) — épreuve ponctuelle orale","4 heures (coefficient 5) — épreuve ponctuelle","6 heures (coefficient 4)"],answer:2,diff:1,explication:"E5 'Intervention sur les systèmes' : 4 heures, coefficient 5, épreuve ponctuelle. Notée sur 20 points. Structure fixe en 3 grandes parties : (1) Prise en charge + préparation (~45 min), (2) Mise en service + mesures (~1h30), (3) Enregistrement numérique + analyse (~45 min + ~1h). Les examinateurs interrogent pendant les 4 heures.",tags:["E5","Structure épreuve","BTS FED","Organisation"]},
  {id:"fed_e5_2",prompt:"Dans la grille d'évaluation de l'E5, quelle compétence a le poids le plus important (40 %) ?",choices:["C7 — Essais et mesures","C8 — Vérifier et adapter les performances","C6 — Outils numériques de pilotage (Kistock RF, tablette CozytouchC, IAQ...)","C9 — Analyse réglementaire"],answer:2,diff:2,explication:"Répartition officielle E5 : C6 (Outils numériques de pilotage) = 40 %, C7 (Essais & mesures) = 30 %, C8 (Vérifier & adapter les performances) = 30 %. Le Kistock RF ou la tablette CozytouchC sont TOUJOURS utilisés en E5 (C6). Maîtriser ces outils numériques est donc capital pour la note.",tags:["E5","C6","Kistock RF","Évaluation","CozytouchC"]},
  {id:"fed_e5_3",prompt:"La formule de la puissance échangée par un fluide eau est :",choices:["Φ = U × S × ΔT","Φ = ṁ × Cp × ΔT (ṁ en kg/s, Cp eau = 4186 J/kg·K, ΔT en K)","Φ = q × ρ × ΔT","Φ = P_élec × COP"],answer:1,diff:1,explication:"Puissance échangée (eau) : Φ (W) = ṁ (kg/s) × Cp_eau (4186 J/kg·K) × ΔT (K). Attention aux conversions : débit en L/h → kg/s : diviser par 3600. Exemple : débit 1 000 L/h = 1000/3600 = 0,278 kg/s. ΔT = T_départ − T_retour. C'est LA formule à maîtriser les yeux fermés pour E5.",tags:["E5","Formule","Puissance","Eau","Bilan thermique"]},
  {id:"fed_e5_4",prompt:"La formule du COP (Coefficient de Performance) d'une pompe à chaleur est :",choices:["COP = P_électrique / Φ_utile","COP = Φ_utile / P_absorbée (Φ_utile = puissance calorifique fournie, P_absorbée = puissance électrique)","COP = Φ_utile × P_absorbée","COP = ΔT_chaud / ΔT_froid"],answer:1,diff:1,explication:"COP = Φ_utile / P_absorbée. Φ_utile = puissance thermique restituée (W ou kW), P_absorbée = puissance électrique consommée (W ou kW). En E5 sujet PAC : mesurer Φ_utile par Φ = ṁ × Cp × ΔT (côté eau), mesurer P_élec avec pince ampèremétrique, calculer COP, puis comparer au COP constructeur (C8-3).",tags:["E5","COP","PAC","Formule","Bilan thermique"]},
  {id:"fed_e5_5",prompt:"Le rendement PCI d'une chaudière se calcule par :",choices:["η = Φ_absorbée / Φ_utile","η = Φ_utile / Φ_absorbée (Φ_absorbée = débit combustible × PCI du combustible)","η = Φ_fumées / Φ_combustible","η = COP × P_élec"],answer:1,diff:2,explication:"Rendement chaudière PCI : η = Φ_utile / Φ_absorbée. Φ_absorbée = qm_combustible × PCI (W). PCI gaz naturel ≈ 10,2 kWh/m³N = 36 720 kJ/m³N. PCI fioul domestique ≈ 11,89 kWh/kg. Φ_utile = ṁ_eau × Cp × ΔT. Chaudière condensation : η PCI > 100% (récupère la chaleur latente de condensation des fumées, ce qui est normal).",tags:["E5","Rendement","Chaudière","PCI","Bilan générateur"]},
  {id:"fed_e5_6",prompt:"L'analyse de combustion complète d'une chaudière gaz ou fioul mesure :",choices:["Uniquement la température des fumées","O₂, CO₂, CO, indice de Bacharach et température des fumées — obligatoire pour le bilan générateur","La pression du gaz en amont du brûleur","Le débit de gaz consommé"],answer:1,diff:1,explication:"Analyse de combustion (appareil dédié, sonde fumées) mesure : O₂ (%), CO₂ (%), CO (ppm), indice de Bacharach (imbrûlés pour fioul), T° fumées. Permet de calculer les pertes par les fumées (Siegert), le rendement, l'excès d'air. CO > 100 ppm = combustion imparfaite → risque intoxication. CO₂ max gaz naturel ≈ 11,8% (stœchiométrie).",tags:["E5","Combustion","Analyseur de combustion","CO","Chaudière gaz","Fioul"]},
  {id:"fed_e5_7",prompt:"Le Kistock RF est utilisé en E5 pour :",choices:["Mesurer la puissance électrique absorbée","L'enregistrement multi-paramètres sans fil en continu (compétence C6 = 40% de la note)","Effectuer l'analyse de combustion","Mesurer le débit d'eau dans les circuits"],answer:1,diff:1,explication:"Kistock RF : système d'enregistrement sans fil (radio fréquence) multi-paramètres. En E5 : configurer le réseau de modules, paramétrer les voies de mesure, lancer l'enregistrement, exporter les données. Correspond à la compétence C6 (40% de la note). Pour chaudière condensation Atlantic : c'est la tablette CozytouchC qui est utilisée à la place.",tags:["E5","Kistock RF","C6","Enregistrement","Numérique"]},
  {id:"fed_e5_8",prompt:"Pour mesurer le débit volumique d'eau dans un circuit hydraulique (E5 — bilan échangeur), quel appareil utiliser ?",choices:["Anémomètre à hélice","Débitmètre PCE-HAWA30 (mesure le débit volumique eau dans les circuits hydrauliques)","Thermo-hygromètre","Analyseur de combustion"],answer:1,diff:2,explication:"Débitmètre PCE-HAWA30 : mesure du débit volumique eau (L/h ou m³/h) dans les circuits hydrauliques (chauffage, ECS, échangeurs). Indispensable pour calculer la puissance échangée Φ = ṁ × Cp × ΔT. À placer sur les circuits concernés. Le jury attend la justification du choix : grandeur mesurée, plage adaptée, procédure de mise en œuvre.",tags:["E5","Débitmètre","PCE-HAWA30","Appareils de mesure","C7-5"]},
  {id:"fed_e5_9",prompt:"L'efficacité d'un échangeur thermique est définie par :",choices:["ε = ΔT_réel × ΔT_max","ε = ΔT_réel / ΔT_max (ΔT_max = T_chaud_entrée − T_froid_entrée)","ε = Φ_utile / Φ_total","ε = rendement × COP"],answer:1,diff:2,explication:"Efficacité échangeur : ε = ΔT_réel / ΔT_max. ΔT_max = écart maximal théorique possible = T_chaud_entrée − T_froid_entrée. ΔT_réel = variation effective de T° du fluide le moins massique. En E5 bilan échangeur sanitaire : calculer ε pour l'échangeur à plaque et l'échangeur multitubulaire, puis comparer aux données constructeur (C8-3).",tags:["E5","Échangeur","Efficacité","Formule","Bilan sanitaire"]},
  {id:"fed_e5_10",prompt:"Quelle est l'ERREUR FATALE la plus fréquente observée en épreuve E5 ?",choices:["Écrire les formules avec des abréviations","Relever les mesures AVANT la stabilisation thermique de l'installation","Choisir trop d'appareils de mesure","Rédiger une conclusion trop longue"],answer:1,diff:1,explication:"Erreur fatale n°1 en E5 : relever avant stabilisation thermique. Il faut attendre minimum 10-15 min après la mise en fonctionnement pour être en régime permanent (températures stables). Un relevé trop précoce = valeurs incorrectes = calculs erronés = mauvaise note sur C7 ET C8. Règle : surveiller les températures et ne commencer les relevés que lorsqu'elles se stabilisent.",tags:["E5","Erreurs","Stabilisation","C7","Méthodologie"]},
  {id:"fed_e5_11",prompt:"La formule de la puissance échangée par un flux d'AIR est :",choices:["Φ = ṁ × Cp × ΔT (idem eau)","Φ = q × ρ × Cp_air × ΔT (q en m³/s, ρ_air ≈ 1,2 kg/m³, Cp_air ≈ 1005 J/kg·K)","Φ = U × S × ΔT","Φ = q × ΔP"],answer:1,diff:2,explication:"Puissance échangée (air) : Φ (W) = q (m³/s) × ρ_air (1,2 kg/m³) × Cp_air (1005 J/kg·K) × ΔT (K). Débit d'air mesuré avec anémomètre : Q = v × S (section de gaine). Application CTA : batterie chaude, batterie froide, calcul puissance soufflée. La valeur ρ × Cp_air ≈ 1206 J/m³·K.",tags:["E5","CTA","Air humide","Formule","Puissance air","Aéraulique"]},
  {id:"fed_e5_12",prompt:"Les données de référence pour les températures extérieures de base (E5 — calculs thermiques) sont :",choices:["Hiver = 0°C (HR 50%), Été = 30°C (HR 60%)","Hiver = −4°C (HR 90%), Été = 35°C (HR 40%) — Températures intérieures : hiver 20°C, été 26°C","Hiver = −10°C, Été = 40°C","Hiver = −2°C (HR 70%), Été = 32°C (HR 50%)"],answer:1,diff:2,explication:"Données de référence E5 à mémoriser : T_ext_hiver = −4°C (HR = 90%), T_ext_été = 35°C (HR = 40%). T_int_hiver = 20°C, T_int_été = 26°C. Cep_ref = 58,4 kWhep/m²/an. Ces valeurs sont utilisées pour les calculs de déperditions, le diagramme de l'air humide et les bilans CTA.",tags:["E5","Données de référence","Température de base","Diagramme de l'air","CTA"]},
  {id:"fed_e5_13",prompt:"En E5, quelle obligation de sécurité doit TOUJOURS être mentionnée dans la procédure d'intervention ?",choices:["Uniquement le port des lunettes de protection","EPI (gants, lunettes, chaussures), consignation électrique, risque brûlure (fluides chauds), risque fuite frigorigène — les examinateurs y sont très attentifs (C7-4)","Uniquement la consignation électrique","Informer le client par écrit avant toute intervention"],answer:1,diff:1,explication:"La sécurité est évaluée en C7-4. Mentionner SYSTÉMATIQUEMENT : EPI (gants isolants, lunettes, chaussures de sécurité), consignation (LOTO — Lock Out Tag Out), risque brûlure (tuyaux chauds, vapeur), risque électrique (armoire BT), risque fuite frigorigène (PAC), risque explosion (chaudière gaz). Omettre la sécurité = perte de points assurée.",tags:["E5","Sécurité","EPI","C7-4","Consignation"]},
  {id:"fed_e5_14",prompt:"La compétence C8-3 évaluée en E5 correspond à :",choices:["Configurer le Kistock RF","Identifier les écarts entre les valeurs constructeur et les valeurs mesurées, et les interpréter (expliquer pourquoi)","Rédiger le schéma de principe","Choisir les appareils de mesure"],answer:1,diff:2,explication:"C8-3 'Analyser les résultats' : le cœur du sujet E5. Toujours : (1) calculer la valeur mesurée, (2) relever la valeur constructeur (dans la documentation fournie), (3) calculer l'écart en %, (4) interpréter : vieillissement, encrassement, conditions d'essai différentes, imprécision de mesure... Ne pas se contenter de constater l'écart — l'EXPLIQUER est ce qui donne les points.",tags:["E5","C8-3","Valeurs constructeur","Analyse","Interprétation"]},
  {id:"fed_e5_15",prompt:"La formule de Siegert (pertes par les fumées) s'écrit :",choices:["qA = (T_fumées + T_air) × (A₁/CO₂ + B)","qA = (T_fumées − T_air) × (A₁/CO₂ + B) — coefficients A₁ et B dépendent du combustible","qA = T_fumées × CO₂ / (T_air × O₂)","qA = CO₂% × T_fumées / 100"],answer:1,diff:3,explication:"Formule de Siegert : qA = (T_fumées − T_air) × (A₁/CO₂ + B). qA = pertes par les fumées en %. T_fumées et T_air en °C. CO₂ en %. A₁ et B : coefficients tabulés selon combustible (gaz naturel : A₁ = 0,68, B = 0,009 ; fioul : A₁ = 0,56, B = 0,007). Permet de calculer les pertes fumées sans mesurer directement le débit de combustible. Utilisée pour tous les sujets 'bilan générateur' chaudière.",tags:["E5","Siegert","Pertes fumées","Chaudière","Combustion","Formule"]},
];

// ─── FICHES ───
export const FICHES_FED = [
  {id:"fed_f1",title:"Systèmes domotiques et GTB",bloc:"Bloc 2",tags:["Domotique","KNX","GTB","BIM"],duree:20,niveau:"Fondations",qbank:"fed_systemes",
    contenu:"**KNX — Standard domotique :**\n• Protocole bus sur paire torsadée (TP) ou IP\n• Adresse individuelle (localisation) + adresse de groupe (fonction)\n• Télégrammes numériques : capteurs → bus → actionneurs\n• Configuration via ETS (Engineering Tool Software)\n• Applications : éclairage, chauffage, volets, comptage énergie\n\n**DALI :** contrôle numérique de l'éclairage (gradation, adressage individuel, scènes)\n\n**GTB (Gestion Technique du Bâtiment) :**\n• Supervision centralisée (Modbus RTU/TCP, BACnet/IP)\n• Automates programmables (régulation CVC)\n• Comptage et reporting énergie\n• Maintenance prédictive\n\n**BIM :** maquette numérique collaborative 3D\n• Logiciels : Revit, ArchiCAD\n• Niveaux LOD (Level of Development) : LOD 100 à LOD 500\n• BIM 4D (planning), 5D (coûts), 6D (exploitation)\n\n**SysML :** modélisation systèmes (9 diagrammes)"},
  {id:"fed_f2",title:"Énergie électrique et installations",bloc:"Bloc 2",tags:["Énergie","Électrotechnique","Protection","Réglementation"],duree:22,niveau:"Intermédiaire",qbank:"fed_energie",
    contenu:"**Puissances électriques :**\n• P (W) = puissance active (travail utile)\n• Q (VAR) = puissance réactive (champs magnétiques)\n• S (VA) = puissance apparente (S² = P² + Q²)\n• cos φ = P/S. Objectif : cos φ proche de 1\n\n**Protection des installations (NF C 15-100) :**\n• Disjoncteur : protection surintensité (court-circuit + surcharge)\n• Différentiel : protection contacts indirects (fuite vers terre)\n  - Type AC : courants sinusoïdaux\n  - Type A : + pulsatoires (lave-linge, VE)\n• Mise à la terre : écoulement des courants de défaut\n• Schémas de liaison à la terre : TT (France résidentiel), TN-S (tertiaire)\n\n**Réglementation thermique RE 2020 :**\n• Bbio (besoin bioclimatique)\n• Cep < 100 kWh/m²/an\n• IC (impact carbone)\n• DPE : A (< 70) → G (> 420 kWh/m²/an)\n\n**Pompe à chaleur :** COP = Pthermique/Pélectrique > 1\n**VMC double flux :** échangeur chaleur (rendement > 80%)"},
  {id:"fed_f3",title:"Réseaux et câblage structuré",bloc:"Bloc 3",tags:["VDI","Réseaux","Câblage","Protocoles"],duree:15,niveau:"Fondations",qbank:"fed_systemes",
    contenu:"**Câblage VDI (Voix-Données-Images) :**\n• Topologie en étoile (centralisé en baie de brassage)\n• Câbles catégorie 6 ou 6A (bande passante 250/500 MHz)\n• FTP (blindé) en environnement industriel, UTP en tertiaire courant\n• Longueur max poste de travail : 90 m + 10 m cordons = 100 m\n\n**Protocoles de communication :**\n• Modbus RTU : liaison série RS485 (maître-esclave)\n• Modbus TCP : Modbus encapsulé dans Ethernet\n• BACnet/IP : bâtiments tertiaires, interopérabilité\n• KNX/IP : KNX via réseau Ethernet existant\n• MQTT : IoT, domotique connectée (publish/subscribe)\n\n**Wi-Fi en bâtiment :**\n• 2.4 GHz (longue portée, plus d'interférences)\n• 5 GHz (plus rapide, portée réduite)\n• PoE (Power over Ethernet) : alimentation et data sur un seul câble"},
  {id:"fed_f4",title:"Analyse et définition d'un système (SysML / FAST)",bloc:"Bloc 1",tags:["SysML","Analyse","Modélisation","Examen"],duree:18,niveau:"Avancé",qbank:"fed_systemes",
    contenu:"**Diagramme des exigences (SysML) :**\n• Capture les fonctions souhaitées et contraintes\n• Liaisons : satisfies, refines, deriveReqt\n\n**Diagramme de blocs (BDD) :**\n• Structure du système (composants, interfaces)\n• Boîte noire → boîte blanche\n\n**Diagramme de cas d'utilisation :**\n• Acteurs + cas d'utilisation + associations\n\n**FAST (Function Analysis System Technique) :**\n• Décomposition fonctionnelle\n• Fonctions de service (FS) : rendues à l'utilisateur\n• Fonctions techniques (FT) : internes au système\n\n**Dossier d'analyse :**\n1. Mise en situation\n2. Diagramme des interacteurs\n3. Diagramme FAST\n4. Diagramme des exigences\n5. Architecture solution"}
  ,{id:"fed_f6",title:"🎓 Annale 2024 — Thermique, hydraulique, eau & combustion",bloc:"Bloc 3",tags:["Annale 2024","Thermique du bâtiment","Résistance thermique","Coefficient U","Reynolds","Eau glycolée","Adoucisseur","Combustion","Méthane","CO","CTA","GTB"],duree:28,niveau:"Avancé",qbank:"fed_thermo2024",
    contenu:"**Contexte (E41+E42 2024 — Musée des Beaux-Arts de Dijon) :**\nRénovation d'un bâtiment patrimonial : forte isolation, CTA double flux, groupes d'eau glacée, sous-station.\n\n**Transfert thermique :**\n• Conduction (solide), convection (fluide), rayonnement (électromagnétique)\n• Rth = e/λ (m²·K/W). Multicouche : Rtot = ΣRth\n• U = 1/Rtot (W/m²·K). RE 2020 : U mur ≤ 0.20, U toit ≤ 0.13\n• Déperditions : Φ = U × S × ΔT\n\n**Hydraulique — Eau glycolée :**\n• MPG (mono propylène glycol) 30% : protection gel ≈ -15°C, non toxique\n• Vitesse v = qv / (π × D²/4)\n• Reynolds Re = ρvD/μ : < 2300 = laminaire, > 4000 = turbulent\n\n**Chimie de l'eau — Adoucisseur :**\n• TH (titre hydrotimétrique) = dureté Ca²⁺ + Mg²⁺. 1°f = 0.1 mmol/L CaCO₃\n• Eau dure → tartre → pertes thermiques circuits chauffage\n• Résine échangeuse de cations : (1) adoucissement R-Na⁺ + Ca²⁺→R-Ca²⁺+Na⁺, (2) saturation, (3) régénération à la saumure NaCl\n\n**Combustion du méthane :**\n• Complète : CH₄ + 2O₂ → CO₂ + 2H₂O (ΔH = -890 kJ/mol)\n• Incomplète (manque O₂) → CO (monoxyde de carbone) : inodore, incolore, mortel\n• CO fixe Hb × 200 > O₂ → hypoxie cérébrale. Détecteur CO obligatoire\n\n**CTA double flux :**\n• Récupérateur de chaleur : air extrait ↔ air neuf (pas de mélange)\n• Rendement 60-90%. Obligatoire RE 2020 tertiaire\n• Batteries chaudes + batteries froides : traitement hygrothermique\n\n**GTB — Régulation PID :**\n• P = proportionnel (erreur), I = intégral (élimine erreur statique), D = dérivé (anticipation)\n• Points TOR (tout-ou-rien) + analogiques (4-20 mA, 0-10V)\n• Protocoles : Modbus RTU/TCP, BACnet/IP"}
  ,{id:"fed_f7",title:"Pompes à chaleur (PAC) : cycles, COP et réglementation",bloc:"Bloc 2",tags:["PAC","COP","SCOP","Cycle frigorifique","Fluides frigorigènes","F-gas","RE 2020"],duree:22,niveau:"Intermédiaire",qbank:"fed_pac",
    contenu:"**Principe de la PAC :**\n• Capte les calories d'une source froide (air, eau, sol) → les restitue à une source chaude\n• 1 kW électrique → 3 à 5 kW thermiques (selon le COP)\n\n**Performances :**\n• COP = P_thermique_utile / P_électrique_consommée (en chauffage)\n• EER = P_froid / P_élec (en refroidissement)\n• SCOP = COP saisonnier (intègre les variations de T° extérieure sur l'année)\n• RE 2020 : SCOP ≥ 2.5\n\n**Cycle thermodynamique (ordre) :**\nÉvaporation (source froide) → Compression → Condensation (source chaude) → Détente\n\n**Bilan thermique :**\nP_chaud = COP × P_élec ; P_froid (captée) = P_chaud - P_élec\n\n**Types de PAC :**\n• Air/Air, Air/Eau, Géothermique eau/eau (COP le plus élevé)\n• Chiller = production d'eau glacée 7/12°C pour tertiaire\n• PAC air/eau + plancher chauffant (35-45°C) = optimum COP\n\n**Fluides frigorigènes :**\n• R32 (PRG 675) remplace R410A (PRG 2088)\n• F-gas UE 517/2014 : restrictions progressives HFC à fort PRG\n• R290 (propane, PRG=3), R744 (CO₂, PRG=1)\n• Certification obligatoire pour techniciens manipulant les fluides"}
  ,{id:"fed_f8",title:"Électrotechnique avancée : moteurs, variateurs et puissance réactive",bloc:"Bloc 2",tags:["Moteur asynchrone","Variateur de fréquence","VFD","Loi cubique","cos φ","TGBT","NF C 15-100","DALI"],duree:22,niveau:"Avancé",qbank:"fed_electro2",
    contenu:"**Moteur asynchrone triphasé :**\n• Cage d'écureuil : robuste, sans balais, courant d'appel 5-8 × In au démarrage direct\n• Glissement s = (Ns - N) / Ns (quelques %)\n\n**Variateur de fréquence (VFD) :**\n• Redresseur → bus DC → onduleur IGBT → AC fréquence et tension variables\n• Rapport V/f constant → maintien du flux magnétique\n• Génère des harmoniques → différentiels type A ou B\n\n**Loi cubique (pompes/ventilateurs) :**\n• Q ∝ N ; ΔP ∝ N² ; P ∝ N³\n• -20% de vitesse → économie de 48.8% sur la puissance absorbée\n• Intérêt majeur des VFD sur les applications CVC\n\n**Puissance réactive :**\n• P (kW) : travail utile ; Q (kVAR) : champs magnétiques ; S (kVA) = √(P²+Q²)\n• cos φ = P/S. Objectif : cos φ > 0.93 (pénalité ENEDIS si < 0.93)\n• Compensation par batteries de condensateurs → ↑ cos φ → ↓ courant I → ↓ pertes Joule\n\n**Protections et installations :**\n• NF C 15-100 : normes BT (France)\n• Différentiel type B : VE, PV, onduleurs (courants DC continus)\n• Schéma IT : neutre isolé → 1ère faute non dangereuse (hôpitaux, industrie)\n• TGBT : armoire principale alimentée depuis le transformateur HTA/BT\n\n**Éclairage LED/DALI :**\n• DALI : protocole numérique 2 fils, adressage individuel, gradation 0-100%, scènes\n• LED : 80-120 lm/W vs halogène 15 lm/W ; driver courant constant\n• Tarif Tempo EDF : 22 jours rouges (HP × 10) → délestage CVC en jours rouges"}
  ,{id:"fed_f9",title:"GTB avancée : protocoles, régulation et IoT",bloc:"Bloc 2",tags:["BACnet","Modbus","KNX","IEC 61131","PID","OPC-UA","LoRaWAN","IoT","PT1000"],duree:22,niveau:"Avancé",qbank:"fed_gtb2",
    contenu:"**Protocoles de communication GTB :**\n• BACnet/IP (ASHRAE 135) : TCP/IP, objets BACnet (Analog Input, Schedule, Trend Log)\n• BACnet MS/TP : RS485 2 fils, jusqu'à 127 maîtres\n• Modbus RTU/TCP : maître-esclave ; Holding registers (4xxxx) = R/W (consignes)\n• KNX adresse individuelle : Zone.Ligne.Appareil (ex: 1.2.5) ; adresse groupe : fonction\n\n**Automates et programmation (IEC 61131-3) :**\n• Ladder (LD) : schéma contacts électriques (historique)\n• FBD : blocs fonctionnels\n• ST (Structured Text) : texte Pascal-like\n• SFC (Grafcet) : processus séquentiels\n• Cycle automate : lecture E/S → traitement programme → écriture sorties\n\n**Régulation automatique :**\n• TOR avec hystérésis : évite les oscillations rapides (ex: chaudière ON à 19°C, OFF à 21°C)\n• Correcteur P : erreur statique résiduelle en régime permanent\n• PID : P + I (élimine erreur statique) + D (anticipe les variations)\n• PT1000 : sonde température, R = 1000 Ω à 0°C, variation ≈ 3.85 Ω/°C\n\n**Supervision GTC et IoT :**\n• OPC-UA : interopérabilité automates ↔ superviseurs ↔ cloud\n• GTC : synoptiques animés, alarmes, historiques, rapports énergie\n• LoRaWAN : capteurs sans-fil longue portée, faible consommation (batterie 5-10 ans)\n• MQTT (publish/subscribe) : protocole IoT cloud\n• VDI cat 6A : 100 m max (90 m câble + 10 m cordons), 10 Gbit/s"}
  ,{id:"fed_f5",title:"Physique appliquée : électricité, thermique, hydraulique",bloc:"Bloc 3",tags:["Physique","Électricité","Thermique","Hydraulique","Acoustique"],duree:20,niveau:"Intermédiaire",qbank:"fed_physique",
    contenu:"**Électricité fondamentale :**\n• U = R×I (Ohm), P = U×I = R×I² = U²/R\n• Lois de Kirchhoff : nœuds (ΣI=0), mailles (ΣU=0)\n• Valeur efficace : Ueff = Umax/√2 → Umax = 325 V pour 230 V\n• Triphasé : S = √3 × UL × IL\n\n**Thermodynamique et isolation :**\n• Rth = e/λ (m²K/W). En série : Rtot = ΣRth\n• Coefficient U = 1/ΣRth (W/m²K). Plus U est petit → meilleure isolation\n• RE 2020 : U mur ≤ 0.20, U toit ≤ 0.13, U vitre ≤ 1.4\n• Ponts thermiques = points faibles (angles, liaisons)\n\n**Mécanique des fluides :**\n• Bernoulli : P + ρgh + ½ρv² = Cte\n• Poiseuille : Q ∝ r⁴ (régime laminaire)\n• Reynolds : Re = ρvD/η. < 2300 = laminaire\n• Darcy-Weisbach : pertes de charge = f × L/D × ρv²/2\n\n**Acoustique :**\n• Niveau sonore L = 10×log(I/I₀) dB\n• +3 dB = ×2 l'intensité\n• Rw = affaiblissement acoustique aérien (dB)"}
  ,{id:"fed_f10",title:"Thermique du bâtiment : déperditions, isolation et RE 2020",bloc:"Bloc 1",tags:["Déperditions thermiques","Coefficient U","Ponts thermiques","RE 2020","Bbio","DPE","Inertie","Isolation","Blower door"],duree:24,niveau:"Intermédiaire",qbank:"fed_thermique_bat",
    contenu:"**Déperditions thermiques totales :**\n• ΦT = Φ_transmission + Φ_renouvellement d'air\n• Transmission : Φ = U × S × ΔT (W/m²K × m² × K)\n• Pont thermique linéique : ΦPT = ψ × L × ΔT\n\n**Composants du coefficient U :**\n• U = 1 / (Rsi + Σ(e/λ) + Rse)\n• Rsi (surface intérieure) ≈ 0.13 m²K/W ; Rse (surface extérieure) ≈ 0.04 m²K/W\n• Plus U est petit → mieux isolé\n\n**Valeurs RE 2020 :**\n• Mur extérieur : U ≤ 0.20 W/m²K\n• Toiture/plancher haut : U ≤ 0.13 W/m²K\n• Plancher bas : U ≤ 0.27 W/m²K\n• Vitrage : Uw ≤ 1.40 W/m²K\n\n**Indicateurs RE 2020 :**\n• Bbio : besoins bioclimatiques (chauffage + refroidissement + éclairage intrinsèques)\n• Cep < 100 kWh_ep/m²/an (5 usages : chauffage, froid, ECS, éclairage, auxiliaires)\n• IC (Impact Carbone) : ACV du bâtiment sur 50 ans\n\n**Inertie thermique :**\n• Matériaux lourds (béton, brique) → fort déphasage thermique → confort d'été\n• Déphasage > 10h (ITE + béton) → pic de chaleur extérieur arrive atténué la nuit\n\n**DPE :** A (< 70) → G (> 420 kWh/m²/an). Passoires F & G : interdiction location progressive 2025-2034\n\n**Étanchéité à l'air :**\n• Test blower door : Q4Pa ≤ 0.60 m³/h.m² (maison BBC)\n• Conductivités λ : laine de roche 0.033-0.040, PUR 0.022-0.025, PSE 0.030-0.038"}
  ,{id:"fed_f11",title:"Aéraulique et ventilation : VMC, CTA, débits et pertes de charge",bloc:"Bloc 2",tags:["VMC simple flux","VMC double flux","CTA","Débit d'air","Pertes de charge","DTU 68.3","Filtration","Aéraulique"],duree:22,niveau:"Intermédiaire",qbank:"fed_aero_ventil",
    contenu:"**Types de VMC :**\n• Simple flux A (SF-A) : débits fixes selon arrêté 1982/DTU 68.3\n• Simple flux B (SF-B / hygroréglable) : bouches variables selon HR\n• Double flux : récupération chaleur échangeur (rendement 75-95%)\n• T° air neuf préchauffé = T_amb + η × (T_int - T_ext)\n\n**Débits réglementaires minimaux (DTU 68.3) :**\n• Cuisine : 45-90 m³/h d'extraction\n• Salle d'eau : 15-30 m³/h\n• WC : 15 m³/h\n• Logements ≥ 5 pièces : débit global min 135 m³/h\n\n**Pertes de charge aérauliques :**\n• Régulières : ΔPr = f × (L/D) × ρv²/2\n• Singulières : ΔPs = ξ × ρv²/2\n• Pression dynamique : Pdyn = ρv²/2 (Pa)\n• Vitesses recommandées : galerie principale 6-8 m/s, terminaux 2-4 m/s\n\n**CTA (Centrale de Traitement d'Air) :**\n• Filtration (G4 puis M5/F7), chauffage, refroidissement, humidification\n• Batterie chaude (eau chaude) + batterie froide (eau glacée ou DX)\n• Free cooling nocturne : refroidissement sans compresseur (T_ext < T_int)\n\n**Qualité de l'air :**\n• Filtres EN ISO 16890 : G4 (grossier) → F7 (fin) → H13 (HEPA)\n• Débit par personne : 25-36 m³/h/pers (bureau, NF EN 13779)\n• CO₂ < 800 ppm (IDA 2) / < 1000 ppm (IDA 3)"}
  ,{id:"fed_f12",title:"Réseaux hydrauliques : chauffage, ECS et pompes",bloc:"Bloc 2",tags:["Pompe centrifuge","HMT","Vase d'expansion","Plancher chauffant","ECS","Légionellose","Équilibrage hydraulique","Vanne 3 voies","Robinet thermostatique"],duree:24,niveau:"Intermédiaire",qbank:"fed_hydraulique",
    contenu:"**Pompes centrifuges :**\n• Point de fonctionnement = intersection courbe pompe (HMT/Q) + courbe réseau (ΔP/Q)\n• HMT (Hauteur Manométrique Totale) = hauteur statique + pertes de charge\n• Pompes en parallèle : double le débit ; en série : double la HMT\n• BEP (Best Efficiency Point) = rendement maximal\n\n**Vase d'expansion à membrane :**\n• Absorbe la dilatation de l'eau (4.3% de 10°C à 90°C)\n• P_gonflage gaz = P_statique du circuit\n• Volume vase : calculé selon EN 12828\n\n**Circuits de chauffage :**\n• Plancher chauffant hydraulique (PCH) : T° départ 35-45°C, idéal pour PAC\n• Vanne 3 voies mélangeuse : mélange eau chaude + retour → T° départ régulée (courbe de chauffe)\n• Robinet thermostatique : régulation locale par pièce (mécanique, sans électricité)\n• Équilibrage hydraulique : STAD / registres d'équilibrage par départ\n\n**ECS collective :**\n• Production : T° ≥ 60°C (destruction Legionella)\n• Distribution : T° ≥ 50°C en tout point (arrêté du 3 mai 2007)\n• Legionella prolifère entre 25-45°C\n• Mitigeur anti-brûlure ≤ 50°C en sortie\n\n**Dimensionnement EF :**\n• Méthode des UC (DTU 60.11 / NF EN 806-3) : simultanéité\n• Vitesse max : 0.5-1 m/s (distribution) ; pertes de charge < 30 Pa/m"}
  ,{id:"fed_f13",title:"Froid et climatisation : cycle de réfrigération, fluides et réglementation",bloc:"Bloc 2",tags:["Diagramme de Mollier","EER","Surchauffe","R32","R290","F-gas","DRV","Tour aéroréfrigérante","TEWI","Réversibilité","Point de rosée"],duree:24,niveau:"Avancé",qbank:"fed_froid_clim",
    contenu:"**Cycle frigorifique — Diagramme de Mollier (h-log P) :**\n• Point 1 (sortie évaporateur) → compression isentropique → Point 2 (sortie compresseur)\n• Point 2 → condensation isobare → Point 3 (sortie condenseur, liquide sous-refroidi)\n• Point 3 → détente isenthalpique → Point 4 (mélange liquide-vapeur basse P)\n• COP = (h1-h4)/(h2-h1) ; EER = idem en mode froid\n\n**Sécurités :**\n• Surchauffe aspiration : 5-10°C (évite le coup de liquide → destruction compresseur)\n• Sous-refroidissement condenseur : 5-10°C (améliore le COP)\n\n**Performances :**\n• EER = P_froid / P_élec ; SEER = EER saisonnier\n• Réversibilité : vanne 4 voies (inverseur de cycle)\n• Chiller : eau glacée 7/12°C pour tertiaire ; TAR = meilleur COP\n\n**Fluides frigorigènes :**\n• R32 : PRG=675, remplace R410A (PRG=2088)\n• R290 (propane) : PRG=3, A3 inflammable\n• R744 (CO₂) : PRG=1, haute pression\n• F-gas UE 517/2014 : quotas HFC, attestation de capacité obligatoire\n\n**Réglementation F-gas :**\n• Contrôle étanchéité : 5-50 t éq. CO₂ → annuel ; > 50 t → semestriel\n• Registre d'installation obligatoire\n• DRV/VRF : une UE + multi-unités intérieures (tertiaire)\n\n**Psychrométrie :**\n• Point de rosée Td : T° de condensation (risque sur surfaces froides)"}
  ,{id:"fed_f14",title:"Énergies renouvelables : solaire, PV, géothermie et réglementation",bloc:"Bloc 1",tags:["Solaire thermique","CESI","PV","Onduleur","MPPT","STC","Géothermie","CET","Biomasse","Free cooling","RGE","Fonds Chaleur"],duree:24,niveau:"Intermédiaire",qbank:"fed_enr",
    contenu:"**Solaire thermique :**\n• CESI (Chauffe-Eau Solaire Individuel) : taux de couverture 50-70%\n• Capteur plan : η ≈ 40-70% selon ΔT et ensoleillement\n• Capteurs à tubes sous vide (CPC) : meilleures performances par faible ensoleillement\n• CET (Chauffe-eau thermodynamique) : PAC air/eau intégrée, COP ≈ 2.5-3.5\n\n**Photovoltaïque (PV) :**\n• Rendement silicium monocristallin : 18-22% (≈ 200 Wc/m²)\n• STC : G = 1000 W/m², T = 25°C, AM 1.5\n• Onduleur : DC → AC (MPPT + synchronisation réseau 50 Hz)\n• Productivité France : 950-1400 kWh/kWc/an (selon région)\n• Performance Ratio (PR) ≈ 75-85%\n\n**Géothermie :**\n• Très basse énergie : sol ≈ 12-15°C → PAC eau/eau, COP 4-5\n• Sondes verticales : 50-200 m ; capteurs horizontaux : 0.8-1.2 m\n• Géothermie de surface : chauffage/climatisation\n\n**Autres ENR :**\n• Biomasse : bilan carbone quasi neutre (cycle court), λ EP = 0.6\n• Éolien : P ∝ v³ (loi cubique). Cp_Betz max = 0.593\n• Coefficient énergie primaire (RE 2020) : électricité = 2.3, gaz = 1.0, bois = 0.6\n\n**Aides et certification :**\n• RGE obligatoire pour bénéficier de MaPrimeRénov' et CEE\n• Fonds Chaleur ADEME : ENR thermiques pour collectivités/entreprises\n• Autoconsommation collective (REACo)\n• Indexation tarif rachat : contrats EDF OA (Obligation d'Achat)"}
  ,{id:"fed_f15",title:"Réglementation du bâtiment : RE 2020, DTU, F-gas, accessibilité",bloc:"Bloc 3",tags:["RE 2020","BBC Rénovation","CEE","F-gas","DTU","CONSUEL","Garantie décennale","Acoustique","Loi Elan","PCAET","RGE"],duree:22,niveau:"Intermédiaire",qbank:"fed_reglementation",
    contenu:"**Réglementation thermique :**\n• RE 2020 (depuis janv. 2022 maisons/logements) : Bbio + Cep < 100 kWh_ep/m²/an + IC carbone\n• BBC Rénovation (Effinergie) : Cep ≤ 80 × Ccoef kWh/m²/an\n• DPE opposable depuis juil. 2021. Interdiction location passoires G : 2025, F : 2028, E : 2034\n\n**Financement rénovation :**\n• CEE : obligations des fournisseurs d'énergie → financent travaux éligibles (isolation, PAC...)\n• MaPrimeRénov' : subvention État via ANAH, cumulable CEE\n• Fonds Chaleur ADEME : ENR thermiques tertiaire, collectivités\n• RGE obligatoire pour aides fiscales\n\n**Normes techniques :**\n• DTU = Document Technique Unifié (règles de l'art par corps de métier)\n  - DTU 68.3 (VMC), DTU 60.11 (plomberie), DTU 45.11 (isolation réseaux)\n• NF EN 12831 : calcul des déperditions thermiques (puissance de chauffage de base)\n• NF C 15-100 : installations électriques BT (France)\n• CONSUEL : attestation de conformité électrique avant mise en service ENEDIS\n\n**Réglementation frigorigènes :**\n• F-gas UE 517/2014 : attestation de capacité obligatoire, registres, contrôles étanchéité\n• Contrôle : annuel (5-50 t éq. CO₂), semestriel (> 50 t)\n\n**Acoustique :** DnT,A ≥ 53 dB entre logements. REI 60 (résistance au feu planchers)\n\n**Responsabilité :** garantie décennale (10 ans, vices compromettant l'ouvrage)\n\n**Urbanisme :** Loi ELAN (2018) : 20% logements neufs accessibles PMR, 100% évolutifs\n\n**Énergie locale :** PCAET obligatoire pour EPCI > 20 000 hab. (transition énergétique locale)"}
  ,{id:"fed_f16",title:"🎓 Guide Épreuve E5 — Intervention sur les systèmes (4h coeff. 5)",bloc:"Bloc 4",tags:["E5","C6","C7","C8","Kistock RF","CozytouchC","Bilan thermique","COP","Combustion","Échangeur","Appareils de mesure","Sécurité","Annales 2026"],duree:35,niveau:"Avancé",qbank:"fed_e5_bilan",
    contenu:"**Épreuve E5 — Cadre général :**\n• 4 heures, coefficient 5, note sur 20, épreuve ponctuelle\n• Jury présent TOUTE l'épreuve → vous êtes interrogés en continu\n• Structure TOUJOURS identique en 3 parties (tous les sujets 2025-2026)\n\n**Compétences évaluées et leur poids :**\n| Compétence | Poids | Ce qu'il faut faire |\n|---|---|---|\n| C6 — Outils numériques | **40%** | Maîtriser Kistock RF / tablette CozytouchC |\n| C7 — Essais & mesures | 30% | Protocole + appareils adaptés + sécurité |\n| C8 — Vérifier performances | 30% | Calculer + comparer constructeur + interpréter |\n\n**Sujets tombés (sessions 2025-2026) :**\n• CTA/PAC York (RJ41) : bilan batterie chaude, bilan PAC complète\n• Chaudière fioul basse T° : bilan générateur + combustion, émetteurs, échangeurs sanitaires\n• Chaudière gaz Condensinox : bilan générateur + combustion, échangeurs (plaque + multitubulaire)\n• PAC air/eau Atlantic Alféa Excellia R410A : calcul COP chaud/froid, comparaison constructeur\n• Chaudière granulés Froling : bilan générateur biomasse, enjeux environnementaux\n• Chaudière gaz condensation Atlantic : mise en service CozytouchC, rendement ≥ 94%\n\n**4 étapes le jour J :**\n1. **Prise en charge (~45 min)** : Compléter schéma de principe, rédiger nomenclature, définir procédure + appareils, identifier capteurs GTC\n2. **Mise en service + mesures (~1h30)** : Mettre en fonctionnement via GTC, attendre stabilisation, relever températures/débits/pressions/HR\n3. **Enregistrement numérique (~45 min)** : Configurer Kistock RF (ou tablette CozytouchC), lancer l'enregistrement, exporter les données\n4. **Calculs + analyse (~1h)** : Calculer puissances/rendements/COP, comparer valeurs constructeur, interpréter écarts, conclure\n\n**Formules indispensables (à maîtriser les yeux fermés) :**\n• **Puissance eau :** Φ = ṁ × Cp × ΔT (Cp_eau = 4186 J/kg·K, ṁ en kg/s)\n• **Puissance air :** Φ = q × ρ × Cp × ΔT (ρ_air ≈ 1,2 kg/m³, Cp_air ≈ 1005 J/kg·K)\n• **COP PAC :** COP = Φ_utile / P_absorbée\n• **Rendement chaudière PCI :** η = Φ_utile / Φ_absorbée (Φ_abs = qm_combustible × PCI)\n• **Débit massique :** ṁ = Q × ρ (Q en m³/s)\n• **Efficacité échangeur :** ε = ΔT_réel / ΔT_max (ΔT_max = T_chaud_entrée − T_froid_entrée)\n• **Pertes fumées (Siegert) :** qA = (T_fumées − T_air) × (A₁/CO₂ + B)\n• **Débit air (CTA) :** Q = v × S\n\n**Données de référence :**\n• T_ext hiver = −4°C (HR 90%) | T_ext été = 35°C (HR 40%)\n• T_int hiver = 20°C | T_int été = 26°C | Cep_ref = 58,4 kWhep/m²/an\n• PCI gaz naturel ≈ 10,2 kWh/m³N | PCI fioul ≈ 11,89 kWh/kg\n\n**Appareils de mesure — lesquels choisir :**\n| Appareil | Mesure | Quand |\n|---|---|---|\n| Thermo-hygromètre | T° + HR air | CTA, ambiance |\n| Thermomètre laser | T° surface (sans contact) | Tuyaux, échangeurs |\n| Thermomètre à contact | T° surface précise | Départ/retour eau |\n| Analyseur de combustion | O₂, CO₂, CO, T° fumées | Chaudière gaz/fioul |\n| Débitmètre PCE-HAWA30 | Débit eau | Circuits hydrauliques |\n| Anémomètre à hélice | Vitesse d'air | Gaines, soufflage |\n| Pince ampèremétrique | Puissance électrique | Compresseur PAC |\n| Kistock RF | Enregistrement multi-capteurs | C6 — toujours utilisé |\n\n**Erreurs fatales à éviter :**\n• ❌ Relever avant stabilisation thermique (attendre 10-15 min minimum)\n• ❌ Oublier les conversions d'unités (L/h → kg/s avant de calculer Φ)\n• ❌ Ne pas comparer aux valeurs constructeur (C8-3 = cœur du sujet)\n• ❌ Rester silencieux face au jury (argumenter même si incomplet)\n• ❌ Omettre les règles de sécurité (EPI, consignation, risque brûlure, frigorigène)\n• ❌ Ne pas conclure chaque partie (conformité ? améliorations ?)\n\n**Checklist avant de rendre :**\n☑ Schéma de principe complété + légende\n☑ Procédure rédigée avec appareils justifiés\n☑ Consignes de sécurité mentionnées\n☑ Relevés effectués APRÈS stabilisation\n☑ Tableau de mesures complet (T°, débits, pressions, HR)\n☑ Analyse de combustion effectuée (si chaudière gaz/fioul)\n☑ Kistock RF / tablette configuré + données exportées\n☑ Tous les calculs avec unités cohérentes (SI)\n☑ Comparaison systématique valeurs mesurées / constructeur\n☑ Écarts IDENTIFIÉS et EXPLIQUÉS\n☑ Résultats dans diagramme de l'air (si CTA)\n☑ Conformité réglementation vérifiée (Arrêté 3 mai 2007, RT existant)\n☑ Au moins 2 propositions d'amélioration concrètes\n☑ Conclusion générale rédigée"}
];

